    class_attributes,
    enrollment_requirements
) VALUES
    ('SPEA-H 456', 'HEALTHCARE REIMBURSEMENT', '2998', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 278', 'Jon Anderson', 20, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course offers students a practical foundation in the systems and structures used to pay for healthcare delivery in the United States. The course is designed to provide students with the required knowledge and skills needed to succeed in entry-level positions within the healthcare setting, including provider organizations, health insurers, medical suppliers and public healthcare financing agencies.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-H 466', 'PUBLIC HEALTH FIELD EXPERIENCE', '4362', 'Class Status', NULL, NULL, 'Lillian Clarke', 46, NULL, 'Practicum', '1', NULL, ARRAY[]::TEXT[], 'Supervised advanced training in professional and technical functions in public health; guided student activity and performance in professional public health functions. Individualized programs may be arranged to suit students'' areas of concentration. Students will be required to fulfill a minimum of 120 hours of professional relevant work.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 466', 'PUBLIC HEALTH FIELD EXPERIENCE', '5971', 'Class Status', NULL, NULL, 'Brian Seavey', 50, NULL, 'Practicum', '1', NULL, ARRAY[]::TEXT[], 'Supervised advanced training in professional and technical functions in public health; guided student activity and performance in professional public health functions. Individualized programs may be arranged to suit students'' areas of concentration. Students will be required to fulfill a minimum of 120 hours of professional relevant work.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 466', 'PUBLIC HEALTH FIELD EXPERIENCE', '10675', 'Class Status', NULL, NULL, 'Megan Starnes', 49, NULL, 'Practicum', '1', NULL, ARRAY[]::TEXT[], 'Supervised advanced training in professional and technical functions in public health; guided student activity and performance in professional public health functions. Individualized programs may be arranged to suit students'' areas of concentration. Students will be required to fulfill a minimum of 120 hours of professional relevant work.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 525', 'HEALTH ECONOMICS FOR POLICY AND MANAGEMENT', '14699', 'Closed', NULL, 'WB WEB', 'Christopher Jackson', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Economic principles play a key role in understanding/improving health policy and management. Health economics applies the tools of the discipline to questions in organization, delivery, and financing to understand health, the health care and health insurance systems, and to critically evaluate current policy debates in the US and globally.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 526', 'HEALTHCARE FINANCE', '14700', 'Class Status', 'TuWTh Tuesday, Wednesday, Thursday 10:00 AM–2:00 PM', 'PV 273', 'Steve Eller', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course focuses on important accounting and financial management principles and concepts relevant to health services and organizations. Through this class, you will learn to: (a) Apply basic financial management and accounting principles in healthcare and public health. (b) Use statistical and analytical tools to measure and improve organizational performance.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 526', 'HEALTHCARE FINANCE', '34222', 'Closed', NULL, 'WB WEB', 'Christopher Jackson', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course focuses on important accounting and financial management principles and concepts relevant to health services and organizations. Through this class, you will learn to: (a) Apply basic financial management and accounting principles in healthcare and public health. (b) Use statistical and analytical tools to measure and improve organizational performance.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 585', 'PRACTICUM 1 IN HEALTHCARE LEADERSHIP', '12340', 'Class Status', 'MW Monday, Wednesday 1:00 PM–3:00 PM', 'HD TBA', 'April Grudi', 7, NULL, 'Practicum', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This MSHM specific course develops the professional skills needed to succeed in healthcare. It includes several national certifications and a written leadership transition plan.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 585', 'PRACTICUM 1 IN HEALTHCARE LEADERSHIP', '14739', 'Class Status', 'Th Thursday 6:00 PM–8:30 PM', 'WB WEB', 'April Grudi', 10, NULL, 'Practicum', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This MSHM specific course develops the professional skills needed to succeed in healthcare. It includes several national certifications and a written leadership transition plan.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 586', 'PRACTICUM 2 IN HEALTHCARE LEADERSHIP', '12341', 'Class Status', 'MW Monday, Wednesday 1:00 PM–3:00 PM', 'HD TBA', 'April Grudi', 7, NULL, 'Practicum', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'To be arranged with host agency and student. A product, such as a practicum report, an oral examination, or examples of materials produced in the practicum, must be approved by the Chairman of the Graduate Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 586', 'PRACTICUM 2 IN HEALTHCARE LEADERSHIP', '14740', 'Class Status', 'Th Thursday 6:00 PM–8:30 PM', 'WB WEB', 'John Newton', 12, NULL, 'Practicum', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'To be arranged with host agency and student. A product, such as a practicum report, an oral examination, or examples of materials produced in the practicum, must be approved by the Chairman of the Graduate Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-I 519', 'DATA BASE MANAGEMENT SYSTEMS', '6258', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A335', 'Roger Morris', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course provides students an in-depth knowledge of database design and management in public organizations. The students create a conceptual, logical, and physical design of databases; build models of data required by users with modeling formalisms and computer-aided software engineering tools; and design queries using leading database software packages.', ARRAY[]::TEXT[], NULL),
    ('SPEA-K 300', 'STATISTICAL TECHNIQUES', '3001', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'OP 105', 'Henry Wakhungu', 2, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Nature of statistical data. Ordering and manipulation of data. Measures of central tendency and dispersion. Elementary probability. Concepts of statistical inference decision: estimation and hypothesis testing. Special topics discussed may include regression and correlation, analysis of variance, nonparametric methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-K 300', 'STATISTICAL TECHNIQUES', '34192', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'PV 167', 'Phoebe Wakhungu', 20, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Nature of statistical data. Ordering and manipulation of data. Measures of central tendency and dispersion. Elementary probability. Concepts of statistical inference decision: estimation and hypothesis testing. Special topics discussed may include regression and correlation, analysis of variance, nonparametric methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-K 300', 'STATISTICAL TECHNIQUES', '2999', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'OP 105', 'Phoebe Wakhungu', 0, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Nature of statistical data. Ordering and manipulation of data. Measures of central tendency and dispersion. Elementary probability. Concepts of statistical inference decision: estimation and hypothesis testing. Special topics discussed may include regression and correlation, analysis of variance, nonparametric methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-K 300', 'STATISTICAL TECHNIQUES', '3000', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'TH A201', 'Henry Wakhungu', 0, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Nature of statistical data. Ordering and manipulation of data. Measures of central tendency and dispersion. Elementary probability. Concepts of statistical inference decision: estimation and hypothesis testing. Special topics discussed may include regression and correlation, analysis of variance, nonparametric methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-K 300', 'STATISTICAL TECHNIQUES', '4833', 'Closed', 'F Friday 10:00 AM–12:00 PM', 'PV 277', 'Henry Wakhungu', 0, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Nature of statistical data. Ordering and manipulation of data. Measures of central tendency and dispersion. Elementary probability. Concepts of statistical inference decision: estimation and hypothesis testing. Special topics discussed may include regression and correlation, analysis of variance, nonparametric methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-K 300', 'STATISTICAL TECHNIQUES', '5264', 'Closed', 'F Friday 12:30 PM–2:30 PM', 'PV 277', 'Henry Wakhungu', 0, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Nature of statistical data. Ordering and manipulation of data. Measures of central tendency and dispersion. Elementary probability. Concepts of statistical inference decision: estimation and hypothesis testing. Special topics discussed may include regression and correlation, analysis of variance, nonparametric methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-L 564', 'LOCAL GOVERNMENT MANAGEMENT', '6495', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV 273', 'Aaron Deslatte', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course deals with the professional management of local communities, with special attention to the forms, processes and policies of cities, towns and counties. Readings and case studies will focus on local government management relating to leadership, planning and operations.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-L 622', 'LOCAL ECONOMIC DEVELOPMENT', '6497', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV 275', 'Mitch Berg', 0, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'This course presents concepts, theories and practices of sustainable local economic development. Lectures, guest speakers, readings and a final applied project will prepare students to provide professional recommendations and analysis of economic development policies and implementation strategies.', ARRAY[]::TEXT[], NULL),
    ('SPEA-M 547', 'NEGOTIATION AND DISPUTE RESOLUTION FOR PUBLIC AFFAIRS', '6498', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 273', 'Daniel Griffith', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Students learn the skill of interest-based negotiation through role-play and simulation. Students will learn about dispute resolution techniques such as mediation, arbitration, fact finding, early neutral evaluation, ombudspersons and facilitation. The course covers dispute resolution in federal government and in the context of public, environmental, labor, and business disputes.', ARRAY[]::TEXT[], NULL),
    ('SPEA-M 561', 'PUBLIC HUMAN RESOURCES MANAGEMENT', '9993', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV 275', 'Cheryl Hughes', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-M 652', 'MANAGING WORK FORCE DIVERSITY IN PUBLIC ORGANIZATIONS', '34211', 'Closed', NULL, 'WB WEB', 'Brian Richardson', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Explores and applies theoretical and empirical research from a management perspective on workforce diversity. Topics include theories and constructs pertaining to diversity in work organizations, organizational postures toward workplace diversity, the interface tween heterogeneity, work processes, and management practice; and the effects of heterogeneity on work-related outcomes.', ARRAY[]::TEXT[], NULL),
    ('SPEA-M 771', 'PUBLIC ORGANIZATION AND MANAGEMENT I', '5397', 'Class Status', 'Tu Tuesday 12:45 PM–3:15 PM', 'PV 270', 'Tom Rabovsky', 10, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'This seminar focuses on management theory in the public sector. Subjects include: historical development, major questions in theory and practice, managerial decision making, and managerial effectiveness.', ARRAY[]::TEXT[], NULL),
    ('SPEA-N 521', 'THE NONPROFIT AND VOLUNTARY SECTOR', '9007', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 163', 'David Bell', 18, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The theory, size, scope, and functions of the nonprofit and voluntary sector are covered from multiple disciplinary perspectives including historical, political, economic, and social.', ARRAY[]::TEXT[], NULL),
    ('SPEA-N 534', 'NGO MANAGEMENT FOR INTERNATIONAL DEVELOPMENT', '10176', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 273', 'Jennifer Brass', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Coursework prepares students for employment in international development. It covers a range of theoretical material and practical skills, answering questions like: What role do NGOs play in developing countries? How do we define and measure NGO success or failure? How do NGOs fundraise, plan, evaluate and collaborate on programs?', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 562', 'PUBLIC PROGRAM EVALUATION', '6511', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A221', 'Antung Liu', 23, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Examination of how the programs of public agencies are proposed, established, operated and evaluated. Discussion of the role and conduct of research in the program process. In addition, techniques of effective evaluation and report presentation are discussed.', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 710', 'TOPICS IN PUBLIC POLICY', '6181', 'Class Status', 'Tu Tuesday 9:30 AM–12:00 PM', 'PV 270', 'Deanna Malatesta', 9, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Doctoral seminar focusing upon various topics in public policy. Illustrative topics include: public management, environmental policy, public finance, and urban affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 710', 'TOPICS IN PUBLIC POLICY', '12272', 'Class Status', 'F Friday 9:00 AM–11:30 AM', 'PV 270', 'Nikolaos Zirogiannis, Kenneth Richards, Aaron Deslatte, Kerry Krutilla', 8, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Doctoral seminar focusing upon various topics in public policy. Illustrative topics include: public management, environmental policy, public finance, and urban affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 710', 'TOPICS IN PUBLIC POLICY', '15282', 'Class Status', 'Tu Tuesday 3:00 PM–5:00 PM', 'HD TBA', 'Jessica Steinberg', 15, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Doctoral seminar focusing upon various topics in public policy. Illustrative topics include: public management, environmental policy, public finance, and urban affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 710', 'TOPICS IN PUBLIC POLICY', '35733', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 270', 'Denvil Duncan', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Doctoral seminar focusing upon various topics in public policy. Illustrative topics include: public management, environmental policy, public finance, and urban affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 762', 'PUBLIC PROGRAM EVALUATION', '11485', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 275', 'Coady Wing', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Examination of how the programs of public agencies are proposed, established, operated and evaluated. Discussion of the role and conduct of research in the program process. In addition, techniques of effective evaluation and report presentation are discussed.', ARRAY[]::TEXT[], NULL),
    ('SPEA-P 791', 'WORKSHOP IN PUBLIC POLICY', '3021', 'Class Status', 'F Friday 12:00 PM–1:30 PM', 'PV A221', 'Jennifer Silva', 13, NULL, 'Seminar', '0–1', 'SPEA', ARRAY[]::TEXT[], 'This workshop focuses on theory and research about public policy. Students are given opportunities to present and critique public policy research and to lead and participate in discussions of selected books and articles.', ARRAY[]::TEXT[], NULL),
    ('SPEA-R 521', 'DOMESTIC ENVIRONMENTAL POLICY', '33449', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV A221', 'Christopher Callahan', 23, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on the actions taken by the national and state governments to protect and improve environmental quality in the United States, emphasizing the role of political actors and institutions. The course provides a survey of the primary laws, regulations, and policies with an emphasis on pollution control.', ARRAY[]::TEXT[], NULL),
    ('SPEA-R 532', 'WATER POLICY AND ECONOMICS', '9008', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 273', 'Nikolaos Zirogiannis', 14, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course provides a throughout review into the current status quo of water quality and water availability policy related issues through the prism of the economics literature. Applications and case studies focus mainly in the US but also expand internationally.', ARRAY[]::TEXT[], NULL),
    ('SPEA-R 535', 'INTERNATIONAL ENVIRONMENTAL POLICY', '10006', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 272', 'Nikolaos Zirogiannis', 6, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Many modern environmental problems are regional or global; policies to address them are complex. We explore several such problems, focusing on climate change and pollution. We study policy details shaping these problems, and examine how international policies create solutions to these issues and how coalitions of countries address these problems.', ARRAY[]::TEXT[], NULL),
    ('SPEA-R 625', 'ENVIRONMENTAL ECONOMICS AND POLICY', '14684', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV A335', 'Kenneth Richards', 31, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course develops the microeconomics-based environmental policy analysis paradigm, and uses the paradigm to evaluate the efficiency of current environmental regulations. The course also explores the incentive issues associated with design of international environmental agreements, and develops techniques (contingent valuation, hedonic pricing, travel cost method) for valuing environmental resources.', ARRAY[]::TEXT[], NULL),
    ('SPEA-R 643', 'NATURAL RESOURCE MANAGEMENT AND POLICY', '10746', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV A205', 'Glen Salmon', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course provides an integrated understanding of science, law, management and policy, preparing students to formulate and initiate policy and manage natural resource programs. Topics covered include program analysis, legal authorities; organizational structure; decision making; and diffusion of innovations. Skills include program implementation and communication with diverse audiences.', ARRAY[]::TEXT[], NULL),
    ('SPEA-S 515', 'SUSTAINABLE COMMUNITIES', '9506', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV A205', 'Aaron Deslatte', 9, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course explores proactive strategies for moving communities toward economic, social and environmental sustainability. Through case studies, projects, tours, and visiting professionals the new thinking in community design, from individual green buildings to regional scales of transportation, land use, commerce, natural systems restoration, waste, food, water, and energy is developed.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 100', 'CURRENT TOPICS IN PUBLIC AFFAIRS', '6248', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:30 PM', 'BQ C110', 'Paul Helmke', 4, NULL, 'Seminar', '1', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Readings and discussion of current public issues and problems.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 100', 'CURRENT TOPICS IN PUBLIC AFFAIRS', '10811', 'Class Status', 'TuTh Tuesday, Thursday 2:45 PM–3:35 PM', 'PV A203', 'Rebecca Gilbert', 5, NULL, 'Seminar', '1', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Readings and discussion of current public issues and problems.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 161', 'URBAN PROBLEMS AND SOLUTIONS', '9467', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'TV 245', 'Mitch Berg', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 181', 'US POLICY AND ADMINISTRATION', '8474', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 167', 'Rachel Carpenter', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The policy making and implementation process in the United States is complex and affects the daily lives of citizens in a profound way. This course will introduce that process and highlight the forces have shaped some of the most salient policy battles of last decade.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 181', 'US POLICY AND ADMINISTRATION', '8475', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 169', 'John Graham', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The policy making and implementation process in the United States is complex and affects the daily lives of citizens in a profound way. This course will introduce that process and highlight the forces have shaped some of the most salient policy battles of last decade.', ARRAY['IUB GenEd S&H credit'], NULL),
