    ('SPEA-V 181', 'US POLICY AND ADMINISTRATION', '12288', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV 169', 'Karl Santiago', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The policy making and implementation process in the United States is complex and affects the daily lives of citizens in a profound way. This course will introduce that process and highlight the forces have shaped some of the most salient policy battles of last decade.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 181', 'US POLICY AND ADMINISTRATION', '14807', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'PV 167', 'Shawna Girgis', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The policy making and implementation process in the United States is complex and affects the daily lives of citizens in a profound way. This course will introduce that process and highlight the forces have shaped some of the most salient policy battles of last decade.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 182', 'POLICY-MAKING AROUND THE WORLD: COMPARATIVE AND INTERNATIONAL APPROACHES', '8477', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 169', 'John Karaagac', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course introduces students to the fields of comparative and international policy. The first part explores how and why governments around the world make policy choices and how these choices affect their citizens. The second part introduces students to how governments work together with other actors to solve global problems.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 182', 'POLICY-MAKING AROUND THE WORLD: COMPARATIVE AND INTERNATIONAL APPROACHES', '8479', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 167', 'Daniel Preston', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course introduces students to the fields of comparative and international policy. The first part explores how and why governments around the world make policy choices and how these choices affect their citizens. The second part introduces students to how governments work together with other actors to solve global problems.', ARRAY['IUB GenEd S&H credit'], NULL),
