    ('SPEA-V 202', 'CONTEMPORARY ECONOMIC ISSUES IN PUBLIC AFFAIRS', '8993', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV 167', 'Daniel Simon', 8, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course reinforces and deepens economic skills by applying basic economic concepts and models to a variety of areas, including tax, social, health, regulatory, environmental, and macroeconomic policy. Issues examined include the motivation for intervention in the economy, the types of intervention, and the predicted effects of policies.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 202', 'CONTEMPORARY ECONOMIC ISSUES IN PUBLIC AFFAIRS', '35246', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BH 104', 'Shuangyu Chen', 42, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course reinforces and deepens economic skills by applying basic economic concepts and models to a variety of areas, including tax, social, health, regulatory, environmental, and macroeconomic policy. Issues examined include the motivation for intervention in the economy, the types of intervention, and the predicted effects of policies.', ARRAY[]::TEXT[], NULL),
