    ('SPEA-V 202', 'CONTEMPORARY ECONOMIC ISSUES IN PUBLIC AFFAIRS', '10293', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 169', 'Alberto Ortega', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course reinforces and deepens economic skills by applying basic economic concepts and models to a variety of areas, including tax, social, health, regulatory, environmental, and macroeconomic policy. Issues examined include the motivation for intervention in the economy, the types of intervention, and the predicted effects of policies.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 202', 'CONTEMPORARY ECONOMIC ISSUES IN PUBLIC AFFAIRS', '30489', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 169', 'Daniel Simon', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course reinforces and deepens economic skills by applying basic economic concepts and models to a variety of areas, including tax, social, health, regulatory, environmental, and macroeconomic policy. Issues examined include the motivation for intervention in the economy, the types of intervention, and the predicted effects of policies.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 203', 'THE CALL OF PUBLIC SERVICE: HISTORY, PHILOSOPHY, VALUES AND OUTCOMES', '11525', 'Class Status', 'W Wednesday 6:30 PM–9:00 PM', 'PV 277', 'Tim Berry', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Many people want to contribute in some positive way to their community, country, or cause. This contribution can be called "public service," which is an important institution pursued widely and valued globally. The course examines its historical evolution, relationships to world religions and philosophies, motivations, values, and outcomes.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 221', 'NONPROFIT AND VOLUNTARY SECTOR', '3083', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:45 AM', 'BH 206', 'Amy Stark', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course provides a broad overview of the U.S. nonprofit sector. Topics include the sector''s size and scope and its religious, historical, and theoretical underpinnings. It also examines perspectives on why people organize, donate to, and volunteer for nonprofit organizations and looks at current challenges that the sector faces.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-V 236', 'MANAGING AND LEADING ORGANIZATIONS', '6098', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 163', 'David Bell', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course introduces domestic and global challenges of management in the public, nonprofit, and private sectors. Examines a range of management concepts and how they can be applied in a contemporary setting. Topics include the organizational environment as well as employee attitudes, cognition, behavior, and performance.', ARRAY['Class uses IU eTexts'], NULL),
