    ('SPEA-V 272', 'TERRORISM AND PUBLIC POLICY', '11278', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'PV 169', 'Susan Siena', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'A survey of the incidence of terrorism around the world. Overviews of ongoing conflicts with terrorist organizations in various countries are interspersed with analyses of significant terrorist events and public policies and responses such events create.', ARRAY['IUB GenEd S&H credit
Class uses IU eTexts'], NULL),
    ('SPEA-V 275', 'INTRODUCTION TO EMERGENCY MANAGEMENT', '6246', 'Closed', 'MW Monday, Wednesday 8:05 PM–9:20 PM', 'PV A201', 'David Henry', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Examination of the background and nature of the profession, the central theoretical debates concerning natural and human-induced disasters, mitigating and reacting to these catastrophic events, and the major roles and responsibilities of emergency managers. Current practical problems and future directions will be explored.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 275', 'INTRODUCTION TO EMERGENCY MANAGEMENT', '34059', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'PV A335', 'Steve Lucas', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Examination of the background and nature of the profession, the central theoretical debates concerning natural and human-induced disasters, mitigating and reacting to these catastrophic events, and the major roles and responsibilities of emergency managers. Current practical problems and future directions will be explored.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 326', 'COMMUNICATION FOR GOVERNMENT AND NONPROFIT ORGANIZATIONS', '11309', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'PV 276', 'Steve Lucas', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will develop an appreciation regarding the critical nature of communication by managers in the public and nonprofit sector. It will introduce students to the skills critical to effective communication as professionals.', ARRAY['Class uses IU eTexts'], NULL),
