    ('SPEA-V 326', 'COMMUNICATION FOR GOVERNMENT AND NONPROFIT ORGANIZATIONS', '30506', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BQ C129', 'Katie Broadfoot', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will develop an appreciation regarding the critical nature of communication by managers in the public and nonprofit sector. It will introduce students to the skills critical to effective communication as professionals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 336', 'MANAGING EXTERNAL COLLABORATION AND NETWORKS', '5993', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 342', 'David Bell', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Course introduces students to the theory, skills, and processes of collaboration. With the rise of infinitely complex issues such as globally linked economies and climate change, there is a move to maximize organizational success by using inter-agency, -firm, or -sectoral collaborations, public/private partnerships, and public engagement.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 339', 'LEGAL HISTORY AND PUBLIC POLICY', '6437', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BQ C105', 'Paul Helmke', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'This course will cover a specific policy issue in American history (such as race relations or political protest/dissent) during specific time periods and focus on the role played by the U. S. Supreme Court in dealing with that issue.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 339', 'LEGAL HISTORY AND PUBLIC POLICY', '8613', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 3079', 'Beth Cate', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'This course will cover a specific policy issue in American history (such as race relations or political protest/dissent) during specific time periods and focus on the role played by the U. S. Supreme Court in dealing with that issue.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 339', 'LEGAL HISTORY AND PUBLIC POLICY', '9052', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV A223', 'Tara Ali', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'This course will cover a specific policy issue in American history (such as race relations or political protest/dissent) during specific time periods and focus on the role played by the U. S. Supreme Court in dealing with that issue.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 346', 'INTRODUCTION TO GOVERNMENT ACCOUNTING AND FINANCIAL REPORTING', '3006', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV A201', 'Antonette McCaster', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'An introduction to government accounting, including comparison with accounting for the private sector; intended as background for the use of financial administrators. The course deals primarily with municipal accounting.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 346', 'INTRODUCTION TO GOVERNMENT ACCOUNTING AND FINANCIAL REPORTING', '32292', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV A201', 'Antonette McCaster', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'An introduction to government accounting, including comparison with accounting for the private sector; intended as background for the use of financial administrators. The course deals primarily with municipal accounting.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 348', 'MANAGEMENT SCIENCE', '6251', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV A201', 'Alexander Alexeev', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Introduction to management-science models and methods for policy analysis and public management. Methods include decision analysis, linear programming, queuing analysis, and simulation. Computer-based applications are included. Prior familiarization with computers is recommended, though not required.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 348', 'MANAGEMENT SCIENCE', '15078', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'LH 035', 'Xiaochun Zhu', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Introduction to management-science models and methods for policy analysis and public management. Methods include decision analysis, linear programming, queuing analysis, and simulation. Computer-based applications are included. Prior familiarization with computers is recommended, though not required.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 361', 'FINANCIAL MANAGEMENT', '8423', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV A201', 'Terri Renner', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Presents the basic theory of financial management and its application to short- and long-term financing decisions by managers. Topics include: financial statement analysis; time value of money; capital budgeting concepts and techniques; securities valuation; cost of capital and optimal capital structure; risk and uncertainty; investment strategy and portfolio management.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 361', 'FINANCIAL MANAGEMENT', '30507', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV 274', 'Rafael Reuveny', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Presents the basic theory of financial management and its application to short- and long-term financing decisions by managers. Topics include: financial statement analysis; time value of money; capital budgeting concepts and techniques; securities valuation; cost of capital and optimal capital structure; risk and uncertainty; investment strategy and portfolio management.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 361', 'FINANCIAL MANAGEMENT', '3659', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV 277', 'Rafael Reuveny', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Presents the basic theory of financial management and its application to short- and long-term financing decisions by managers. Topics include: financial statement analysis; time value of money; capital budgeting concepts and techniques; securities valuation; cost of capital and optimal capital structure; risk and uncertainty; investment strategy and portfolio management.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 362', 'NONPROFIT MANAGEMENT AND LEADERSHIP', '11242', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BQ C129', 'Laura Littlepage', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Students in this experiential course prepare themselves for this field as well as public and private sector jobs that intersect with the nonprofit sector. This course provides an overview of nonprofit management practices, including governance, leadership, planning, performance measurement, marketing, finances, ethics, team management, and staff and volunteer relations.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 365', 'URBAN DEVELOPMENT AND PLANNING', '13957', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AD A152', 'Mitch Berg', 35, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'This course identifies the major problems associated with urban development in the U.S. and investigates the potential of public planning strategies and tools to deal with these problems. An emphasis is placed on the application of analytical approaches to problem definition and solution.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 369', 'MANAGING INFORMATION TECHNOLOGY', '3593', 'Class Status', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'PV 277', 'T.C. Bradley', 11, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Analysis and discussion of information technology as applied to problem solving and management in public and non-profit sectors. Topics include management, infrastructures, policies, and concepts such as scalability, manageability, security, and cost of technology. Focus is on high-level issues surrounding IT and the strategic positioning of IT in all sectors of business.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 369', 'MANAGING INFORMATION TECHNOLOGY', '3008', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'PV 276', 'Jacob Farmer', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Analysis and discussion of information technology as applied to problem solving and management in public and non-profit sectors. Topics include management, infrastructures, policies, and concepts such as scalability, manageability, security, and cost of technology. Focus is on high-level issues surrounding IT and the strategic positioning of IT in all sectors of business.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 370', 'RESEARCH METHODS AND STATISTICAL MODELING', '10295', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'PV A201', 'Alexander Alexeev', 9, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will introduce the student to the basic methods, issues, analytical techniques, and ethical considerations of evaluation research.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 370', 'RESEARCH METHODS AND STATISTICAL MODELING', '33772', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV A221', 'Alexander Alexeev', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will introduce the student to the basic methods, issues, analytical techniques, and ethical considerations of evaluation research.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 370', 'RESEARCH METHODS AND STATISTICAL MODELING', '8424', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GA 1100', 'Alexander Alexeev', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will introduce the student to the basic methods, issues, analytical techniques, and ethical considerations of evaluation research.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 371', 'FINANCING PUBLIC AFFAIRS', '6440', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'PV 167', 'Philip Lehmkuhler', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'A survey of economic and political theories of market failures, public expenditure evaluation, economic stabilization, systems of redistribution, and fiscal federalism. Examples and applications to contemporary government decisions.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 373', 'HUMAN RESOURCES MANAGEMENT IN THE PUBLIC SECTOR', '6250', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV 272', 'Cheryl Hughes', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 373', 'HUMAN RESOURCES MANAGEMENT IN THE PUBLIC SECTOR', '8483', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'LI 503', 'Daniel Grundmann', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 373', 'HUMAN RESOURCES MANAGEMENT IN THE PUBLIC SECTOR', '9817', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'PV 276', 'Christopher Schrader', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 373', 'HUMAN RESOURCES MANAGEMENT IN THE PUBLIC SECTOR', '11799', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 2101', 'Christopher Schrader', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 373', 'HUMAN RESOURCES MANAGEMENT IN THE PUBLIC SECTOR', '12446', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 272', 'Natalia Rayzor', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 373', 'HUMAN RESOURCES MANAGEMENT IN THE PUBLIC SECTOR', '13958', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'PV A335', 'Neil Smith', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 374', 'INTERMEDIATE PUBLIC BUDGETING AND FINANCE FOR PUBLIC AFFAIRS', '9474', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'PV 272', 'John Shassberger', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The public and non-profit sectors provide resources and produce goods and services that are crucial for a well-functioning society. This requires plans for production, financing, and accounting. This course uses V186 as a base to explore these issues.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 374', 'INTERMEDIATE PUBLIC BUDGETING AND FINANCE FOR PUBLIC AFFAIRS', '14595', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:45 AM', 'WH 009', 'Denvil Duncan', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The public and non-profit sectors provide resources and produce goods and services that are crucial for a well-functioning society. This requires plans for production, financing, and accounting. This course uses V186 as a base to explore these issues.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 374', 'INTERMEDIATE PUBLIC BUDGETING AND FINANCE FOR PUBLIC AFFAIRS', '34782', 'Closed', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'PV 272', 'John Shassberger', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The public and non-profit sectors provide resources and produce goods and services that are crucial for a well-functioning society. This requires plans for production, financing, and accounting. This course uses V186 as a base to explore these issues.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 378', 'FEDERAL GOVERNMENT PROCESSES', '3151', 'Class Status', 'M Monday 6:30 PM–9:00 PM', 'HD TBA', 'Brian Volsky', 12, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'In this course, through detailed examination of the legislative process, the budget process and the regulatory process, students will explore Federal Government processes and how they aid and hinder programmatic implementation. The skills and knowledge discussed in this class help students understand the inner workings of the Federal Government.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 379', 'PERFORMANCE MEASUREMENT AND PROGRAM EVALUATION', '5488', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 1112', 'Mindy King', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course provides an overview of program evaluation as it relates to public affairs, criminal justice, health policy, and environmental science with particular emphasis on measuring program outcomes. The course is designed for students who envision themselves working in management, policy making, or research roles.', ARRAY['Class uses IU eTexts'], NULL),
