    ('SPEA-V 381', 'PROFESSIONAL EXPERIENCE', '3011', 'Class Status', NULL, NULL, 'Lillian Clarke', 92, NULL, 'Independent Study', '1', NULL, ARRAY[]::TEXT[], 'Students will be required to fulfill a minimum of 120 hours of professional relevant work.', ARRAY[]::TEXT[], NULL),
