    ('SPEA-V 386', 'CASE STUDIES FOR POLICY ANALYSIS', '3013', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV A205', 'Sameeksha Desai', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on analyzing case studies of public policies using a variety of disciplinary perspectives including application of the principles and concepts of intermediate microeconomic theory.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 386', 'CASE STUDIES FOR POLICY ANALYSIS', '34182', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV A205', 'Sameeksha Desai', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on analyzing case studies of public policies using a variety of disciplinary perspectives including application of the principles and concepts of intermediate microeconomic theory.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 390', 'READINGS IN PUBLIC AND ENVIRONMENTAL AFFAIRS', '37455', 'Closed', NULL, NULL, 'Andrea Need', 0, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings and research related to a topic of special interest to the student. Written report required.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 401', 'FINANCIAL AND COST-BENEFIT ANALYSIS', '3014', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV A335', 'Annie Hsu', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarizes students with the principles of financial analysis, cost-benefit analysis, and Kaldor/Hicks accounting. Topics include net present value calculation; net annual worth; public and private decision criteria; and market data adjustment for taxes, rents, and other market distortions.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 401', 'FINANCIAL AND COST-BENEFIT ANALYSIS', '30509', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV 276', 'Annie Hsu', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarizes students with the principles of financial analysis, cost-benefit analysis, and Kaldor/Hicks accounting. Topics include net present value calculation; net annual worth; public and private decision criteria; and market data adjustment for taxes, rents, and other market distortions.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 401', 'FINANCIAL AND COST-BENEFIT ANALYSIS', '35114', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV A201', 'Annie Hsu', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarizes students with the principles of financial analysis, cost-benefit analysis, and Kaldor/Hicks accounting. Topics include net present value calculation; net annual worth; public and private decision criteria; and market data adjustment for taxes, rents, and other market distortions.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 405', 'PUBLIC LAW AND THE LEGISLATIVE PROCESS', '3015', 'Closed', 'W Wednesday 3:55 PM–6:25 PM', 'PV A201', 'John Gregg', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course focuses on Congress as a policy making body in the U.S. public law system. It covers the Constitutional framework for Congressional operations as well as technical aspects of the legislative process such as bill drafting and analysis, the role of leadership, and the prerogatives of individual members.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 407', 'ADVOCACY, POLICY CHANGE, AND GOVERNMENT RELATIONS', '7825', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 277', 'Elise Shrock', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This class explores advocacy: the processes by which citizens join together to shape issues of public importance. Includes: historical evolution of organized interests, philosophical underpinnings of right to petition the government, means by which individuals and interest groups affect policy, and challenges of advocating for change through governmental processes.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 409', 'FEDERAL POLICYMAKING AND THE HEARING PROCESS', '8994', 'Class Status', 'F Friday 9:00 AM–12:00 PM', 'HD TBA', 'Brian Volsky', 12, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Using a structured speaker series as a base, this class exposes students to policy decision makers in the legislative and executive branches. The class requires students attend Congressional hearings, write hearing memos, and finishes the semester with a student run mock hearing.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 412', 'LEADERSHIP AND ETHICS', '8596', 'Closed', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'PV A335', 'Kirk White', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course is designed to examine the complex leadership issues and challenges facing communities and explore how citizens and government can work together to address these challenges. This includes exploration of how the problems, conflicts, and dilemmas encountered by leaders when making decisions must be considered within an ethical framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 412', 'LEADERSHIP AND ETHICS', '30510', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 277', 'Claudia Avellaneda', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course is designed to examine the complex leadership issues and challenges facing communities and explore how citizens and government can work together to address these challenges. This includes exploration of how the problems, conflicts, and dilemmas encountered by leaders when making decisions must be considered within an ethical framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 414', 'NATIONAL SECURITY BUREAUCRACY & POLICY', '12506', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV A201', 'John Karaagac', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course is designed for students interested in US national security and bureaucracy policy and process, who want to work in the field, or who want to understand the nature of international security threats to the US. Course traces foundations, evolution, and future of national security bureaucracy and the policy process.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 415', 'DATA SCIENCE IN PUBLIC AND ENVIRONMENTAL AFFAIRS', '33504', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 274', 'Roger Morris', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course provides a practical experience for students to acquire useful, marketable skills in Data Science. Students will learn to effectively manage and analyze data with the purpose of finding solutions to difficult or complex issues and communicate findings to a larger audience.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 424', 'ENVIRONMENTAL LAW, JUSTICE, AND POLITICS', '8995', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 277', 'David Konisky', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'An introduction to U.S. environmental politics and policy, focusing on the institutions and political actors involved in environmental protection. It emphasizes the difficult political, economic, and social justice questions that arise in the context of managing current and future public health and ecological risks.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 425', 'HOMELAND SECURITY: POLICY AND PRACTICE', '8999', 'Closed', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'PV A201', 'David Henry', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course examines homeland security policy through its practice in security agencies. Students will analyze primary sources and policy objectives, and survey U.S. homeland security through historical and recent incidents. Students will evaluate current events, and their implications for federalism, fiscal policy, civil liberties and future policymaking.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 434', 'NGO MANAGEMENT FOR INTERNATIONAL DEVELOPMENT', '10622', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 273', 'Jennifer Brass', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Coursework prepares students for employment in international development. It covers a range of theoretical material and practical skills, answering questions like: What role do NGOs play in developing countries? How do we define and measure NGO success or failure? How do NGOs fundraise, plan, evaluate and collaborate on programs?', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 435', 'NEGOTIATION AND ALTERNATIVE DISPUTE RESOLUTION', '32293', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'LH 035', 'Gary Branham', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course introduces students to the theories and techniques of alternative dispute resolution. The course covers interest-based negotiation, mediation, arbitration, fact finding, early neutral evaluation, and other techniques used in business, labor relations, environmental disputes, family relations, and international affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 435', 'NEGOTIATION AND ALTERNATIVE DISPUTE RESOLUTION', '3016', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'LH 130', 'Gary Branham', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course introduces students to the theories and techniques of alternative dispute resolution. The course covers interest-based negotiation, mediation, arbitration, fact finding, early neutral evaluation, and other techniques used in business, labor relations, environmental disputes, family relations, and international affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 435', 'NEGOTIATION AND ALTERNATIVE DISPUTE RESOLUTION', '3017', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'LH 035', 'Gary Branham', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course introduces students to the theories and techniques of alternative dispute resolution. The course covers interest-based negotiation, mediation, arbitration, fact finding, early neutral evaluation, and other techniques used in business, labor relations, environmental disputes, family relations, and international affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 435', 'NEGOTIATION AND ALTERNATIVE DISPUTE RESOLUTION', '8484', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:55 PM', 'PV A335', 'Daniel Griffith', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course introduces students to the theories and techniques of alternative dispute resolution. The course covers interest-based negotiation, mediation, arbitration, fact finding, early neutral evaluation, and other techniques used in business, labor relations, environmental disputes, family relations, and international affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 437', 'PUBLIC TRANSPORTATION', '30511', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV A223', 'Perry Maull', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The class will explore the basis of passenger transportation, including the modes of bus, rail, paratransit, and taxi. Passenger Transportation Management Elements: Human resources, Finance, Operations, Scheduling, Maintenance, and Planning. Federal Policy; Program funding options,: Policy development, Interagency programs, and the Federal Authorization process. Mobility options: Volunteer programs, Car sharing, Ridesharing, and Coordinated programs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 439', 'DEBATES IN PUBLIC FINANCE', '8558', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV A205', 'John Shassberger', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarizes students with the tools required to objectively analyze the potential impacts of various government policies. It covers important policies at the federal, state and local levels of government including income, sales taxes and property taxes, and mandatory and discretionary spending. Debt administration is also included.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 439', 'DEBATES IN PUBLIC FINANCE', '32294', 'Closed', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'PV A205', 'Philip Lehmkuhler', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarizes students with the tools required to objectively analyze the potential impacts of various government policies. It covers important policies at the federal, state and local levels of government including income, sales taxes and property taxes, and mandatory and discretionary spending. Debt administration is also included.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 443', 'MANAGING WORK FORCE DIVERSITY', '6632', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'PV 272', 'Natalia Rayzor', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The composition and nature of the work force is changing. Managers must decide how to accommodate real differences among the members of their organizations. This course seeks to provide information for practitioners who hope to integrate an understanding of work force diversity into their management style and professional behavior.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 443', 'MANAGING WORK FORCE DIVERSITY', '11243', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV A223', 'Samanta Fonseca', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The composition and nature of the work force is changing. Managers must decide how to accommodate real differences among the members of their organizations. This course seeks to provide information for practitioners who hope to integrate an understanding of work force diversity into their management style and professional behavior.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 450', 'CONTEMPORARY ISSUES IN PUBLIC AFFAIRS', '5265', 'Class Status', 'WTh Wednesday, Thursday 7:05 PM–10:00 PM', 'PV 275', 'Brian DeLong', 9, NULL, 'Seminar', '1', 'SPEA', ARRAY[]::TEXT[], 'Extensive analysis of selected contemporary issues in public affairs. Topics vary from semester to semester.', ARRAY['Class uses IU eTexts'], NULL),
