    ('SPEA-V 456', 'TOPICS IN PUBLIC LAW', '9050', 'Class Status', 'Tu Tuesday 4:00 PM–6:30 PM', 'LW 122', 'Timothy Waters', 21, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Extensive analysis of selected contemporary issues in public law. Topics vary from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 456', 'TOPICS IN PUBLIC LAW', '9051', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LW 122', 'Nicholas Almendares', 0, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Extensive analysis of selected contemporary issues in public law. Topics vary from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 458', 'FUND DEVELOPMENT FOR NONPROFIT ORGANIZATIONS', '11269', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 163', 'Hillary Person', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course builds an understanding of the practice, philosophy, law, and theory of fundraising. Students establish an organization''s value base and mission, prepare funding appeals, evaluate readiness for a campaign, assess funding sources, implement fundraising vehicles, evaluate effectiveness, and discuss stewardship of contributions.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 461', 'CLOUD COMPUTING APPLICATIONS IN PUBLIC AFFAIRS', '12330', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV A335', 'Alan Walsh', 23, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course is designed to provide students with the essentials of cloud computing needed to operate effectively in a public affairs environment. The course will emphasize public affairs applications using software packages and services.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 462', 'COMMUNITY DEVELOPMENT', '4499', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PY 109', 'Robert Burgins', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-V 475', 'DATABASE MANAGEMENT SYSTEMS', '6252', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A335', 'Roger Morris', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Students learn contemporary theories and methodologies regarding design, use, and management of database systems among public-sector organizations. The course provides hands-on experience with tools such as entity-relationship diagrams, query languages, database management software, and an understanding of critical database management issues such as security, backup, and recovery.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 476', 'COMPENSATION STRATEGY AND SYSTEMS', '8497', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'AC C002', 'Kathleen Stedman', 10, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'The purpose of this course is to understand the complexity behind successful compensation systems that link organizations to the people they employ. Students will study topics of direct and indirect compensation, internal and external pay equity, and theories of public service motivation and how they apply to the three sectors.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 477', 'STRATEGIC HUMAN RESOURCE MANAGEMENT', '32834', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 163', 'Dave Archer', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This class covers the fundamental elements of Strategic Human Resource Management. The course builds on students'' foundation of knowledge of HR methods and practices from the perspective of managers and practitioners working in the public and non-profit sectors.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 477', 'STRATEGIC HUMAN RESOURCE MANAGEMENT', '6445', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV 278', 'Daniel Grundmann', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This class covers the fundamental elements of Strategic Human Resource Management. The course builds on students'' foundation of knowledge of HR methods and practices from the perspective of managers and practitioners working in the public and non-profit sectors.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 478', 'EMPLOYMENT LAW FOR HUMAN RESOURCES MANAGEMENT', '6103', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'PV 278', 'Kathryn Cimera', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on employment laws that are relevant to the Human Resource manager. Students will study employment laws and court cases that will provide them with the practical legal knowledge they need as a future HR professional working in the public and/or non-profit sectors.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 478', 'EMPLOYMENT LAW FOR HUMAN RESOURCES MANAGEMENT', '8488', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV A221', 'Dave O''Guinn', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on employment laws that are relevant to the Human Resource manager. Students will study employment laws and court cases that will provide them with the practical legal knowledge they need as a future HR professional working in the public and/or non-profit sectors.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 479', 'EMPLOYEE RECRUITMENT AND SELECTION IN THE PUBLIC SECTOR', '6446', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV A223', 'Cheryl Hughes', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will provide an in-depth examination of organizational staffing process in the public sector but is also relevant to the private and non-profit sectors. Effective employee selection and talent utilization for increasing organizational effectiveness will be covered. Other topics include the planning process, retention, and identifying talent.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 481', 'GRANT WRITING FOR PUBLIC AND NONPROFIT ORGANIZATIONS', '34060', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:30 PM', 'GA 1106', 'Bridget Anderson', 3, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The purpose of this course is to prepare students for grant proposal development. Students will explore various skills including how to identify appropriate grant sources; conceptualize, write and submit a grant proposal for funding; prepare a grant budget; and evaluate grant proposals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 481', 'GRANT WRITING FOR PUBLIC AND NONPROFIT ORGANIZATIONS', '13960', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BQ C129', 'Laura Littlepage', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The purpose of this course is to prepare students for grant proposal development. Students will explore various skills including how to identify appropriate grant sources; conceptualize, write and submit a grant proposal for funding; prepare a grant budget; and evaluate grant proposals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 490', 'DIRECTED RESEARCH IN PUBLIC AFFAIRS', '15294', 'Class Status', NULL, 'HD TBA', 'Andrea Need', 10, NULL, 'Research', '0–3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'To be arranged with the individual instructor and approved by the chairman of the Undergraduate Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 491', 'HONORS RESEARCH IN PUBLIC AND ENVIRONMENTAL AFFAIRS', '11281', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 141', 'Paolo Belardinelli', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Approval of instructor and SPEA Honors advisor. Restricted to students in SPEA Honors Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 491', 'HONORS RESEARCH IN PUBLIC AND ENVIRONMENTAL AFFAIRS', '13072', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 275', 'Allison Schnable', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Approval of instructor and SPEA Honors advisor. Restricted to students in SPEA Honors Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 499', 'HONORS THESIS', '8998', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV A203', 'Matthew Baggetta', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Research and paper to be arranged with individual instructor and approved by the campus SPEA Honors Program Director.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 499', 'HONORS THESIS', '32295', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV A203', 'Jennifer Silva', 8, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Research and paper to be arranged with individual instructor and approved by the campus SPEA Honors Program Director.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 506', 'STATISTICAL ANALYSIS FOR EFFECTIVE DECISION MAKING', '9009', 'Class Status', 'TuTh Tuesday, Thursday 6:30 PM–7:45 PM', 'PV A221 PV 274', 'Shellye Suttles', 20, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Non-calculus survey of concepts in probability, estimation, and hypothesis testing. Applications of contingency table analysis; analysis of variance, regression, and other statistical techniques. Computer processing of data emphasized.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 506', 'STATISTICAL ANALYSIS FOR EFFECTIVE DECISION MAKING', '11244', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV A221 PV A221', 'Tom Rabovsky', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Non-calculus survey of concepts in probability, estimation, and hypothesis testing. Applications of contingency table analysis; analysis of variance, regression, and other statistical techniques. Computer processing of data emphasized.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 506', 'STATISTICAL ANALYSIS FOR EFFECTIVE DECISION MAKING', '11803', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A223 PV A223', 'Barry Rubin', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Non-calculus survey of concepts in probability, estimation, and hypothesis testing. Applications of contingency table analysis; analysis of variance, regression, and other statistical techniques. Computer processing of data emphasized.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 506', 'STATISTICAL ANALYSIS FOR EFFECTIVE DECISION MAKING', '8067', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A223 PV A223', 'Barry Rubin', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Non-calculus survey of concepts in probability, estimation, and hypothesis testing. Applications of contingency table analysis; analysis of variance, regression, and other statistical techniques. Computer processing of data emphasized.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-V 512', 'PUBLIC POLICY PROCESS', '9477', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV A223', 'Paolo Belardinelli', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'An examination of the role of public affairs professionals in policy processes. Focuses on relationships with political actors in various policy areas.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 517', 'PUBLIC MANAGEMENT ECONOMICS', '3018', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV A221', 'Kenneth Richards', 6, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Provides the student with the central core of economic theory as it relates to the public sector. The use of micro-economic skills at the managerial level in the public sector is emphasized. The course includes a unit on macro-economics to include monetary theory, fiscal theory, economic stabilization, national income accounts.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 517', 'PUBLIC MANAGEMENT ECONOMICS', '9989', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 272', 'Kenneth Richards', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Provides the student with the central core of economic theory as it relates to the public sector. The use of micro-economic skills at the managerial level in the public sector is emphasized. The course includes a unit on macro-economics to include monetary theory, fiscal theory, economic stabilization, national income accounts.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 535', 'MANAGING AND LEADING IN PUBLIC AFFAIRS', '12275', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 277', 'Amanda Rutherford', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The course allows students to develop skills and competencies to become effective managers and leaders in organizations pursuing the public interest. It draws from the organization theory and organizational behavior, leadership, and public and nonprofit management literatures for insight into the critical role of management and leadership in governance.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 536', 'RIGHTS AND RESPONSIBILITIES: HOW LAW SHAPES PUBLIC AFFAIRS', '12276', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A201', 'Andrea Need', 24, NULL, 'Lecture', '1.5', 'SPEA', ARRAY[]::TEXT[], 'Explanation of law in society and its influence on public-sector operations. Examination of central legal principles shaping American governance including the rule of law, supremacy and preemption, due process and equal protection, statutory interpretation, and judicial review of administrative agency action, among others.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 536', 'RIGHTS AND RESPONSIBILITIES: HOW LAW SHAPES PUBLIC AFFAIRS', '12277', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A201', 'Andrea Need', 35, NULL, 'Lecture', '1.5', 'SPEA', ARRAY[]::TEXT[], 'Explanation of law in society and its influence on public-sector operations. Examination of central legal principles shaping American governance including the rule of law, supremacy and preemption, due process and equal protection, statutory interpretation, and judicial review of administrative agency action, among others.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 550', 'TOPICS IN PUBLIC AFFAIRS', '12509', 'Class Status', 'Th Thursday 6:30 PM–9:00 PM', 'HD TBA', 'John McClelland', 11, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Selected research and discussion topics organized on a semester-by-semester basis, usually with significant student input in the course design.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 550', 'TOPICS IN PUBLIC AFFAIRS', '14145', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV A335', 'Alan Walsh', 23, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Selected research and discussion topics organized on a semester-by-semester basis, usually with significant student input in the course design.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 580', 'READINGS IN PUBLIC AFFAIRS', '3019', 'Class Status', NULL, NULL, 'Jill Nicholson-Crotty', 30, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Readings on selected topics in public affairs.', ARRAY[]::TEXT[], NULL),
