    ('SPEA-V 582', 'OVERSEAS TOPICS IN PUBLIC AFFAIRS', '5585', 'Class Status', NULL, NULL, 'Ashley Hosseini', 3, NULL, 'Lecture', '0–15', NULL, ARRAY[]::TEXT[], 'SPEA Abroad Graduate Program: study of selected topics in public affairs. Topics vary from semester to semester. May be repeated for credit.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 582', 'OVERSEAS TOPICS IN PUBLIC AFFAIRS', '12927', 'Class Status', NULL, NULL, 'Ashley Hosseini', 4, NULL, 'Lecture', '0–15', NULL, ARRAY[]::TEXT[], 'SPEA Abroad Graduate Program: study of selected topics in public affairs. Topics vary from semester to semester. May be repeated for credit.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 582', 'OVERSEAS TOPICS IN PUBLIC AFFAIRS', '12928', 'Class Status', NULL, NULL, 'Ashley Hosseini', 4, NULL, 'Lecture', '0–15', NULL, ARRAY[]::TEXT[], 'SPEA Abroad Graduate Program: study of selected topics in public affairs. Topics vary from semester to semester. May be repeated for credit.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 585', 'PRACTICUM IN PUBLIC AFFAIRS', '7970', 'Class Status', NULL, NULL, 'Celeste Ross', 128, NULL, 'Independent Study', '0–6', NULL, ARRAY[]::TEXT[], 'To be arranged with host agency and student on a case-by-case basis. The amount of credit must be approved before the beginning of the practicum. A product, such as a practicum report, an oral examination, or examples of materials produced in the practicum, must be approved by the Chairman of the Graduate Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 585', 'PRACTICUM IN PUBLIC AFFAIRS', '9820', 'Class Status', NULL, NULL, 'Michele Lersch', 15, NULL, 'Independent Study', '0–6', NULL, ARRAY[]::TEXT[], 'To be arranged with host agency and student on a case-by-case basis. The amount of credit must be approved before the beginning of the practicum. A product, such as a practicum report, an oral examination, or examples of materials produced in the practicum, must be approved by the Chairman of the Graduate Program.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 590', 'RESEARCH IN PUBLIC AFFAIRS', '3020', 'Class Status', NULL, NULL, 'Jill Nicholson-Crotty', 29, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Research on selected topics in public affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 590', 'RESEARCH IN PUBLIC AFFAIRS', '6331', 'Class Status', NULL, NULL, 'Jill Nicholson-Crotty', 30, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Research on selected topics in public affairs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 600', 'CAPSTONE IN PUBLIC AND ENVIRONMENTAL AFFAIRS', '6575', 'Class Status', NULL, 'PV A205', 'Jennifer Brass, Kathy Fisher', 6, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Interdisciplinary course organized as faculty-coached class project on a management/policy topic determined by an external client. Course goals are professional preparation and integration of degree program knowledge.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 706', 'STATISTICS FOR RESEARCH IN PUBLIC AFFAIRS I', '4463', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 275 PV 275', 'Coady Wing', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Focus is on estimation of model parameters using least squares methods. Topics include properties of estimators, ordinary least squares, instrumental variables, two- and three-stage least squares, assumptions, consequences when assumptions false, and alternate methods when assumptions false. Emphasis on matrix representations and simulation methods.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 780', 'RESEARCH DESIGN AND METHODS IN PUBLIC AFFAIRS', '10207', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV 163', 'Amanda Rutherford', 13, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Three major areas will be covered: philosophy of science, theory and design of research, and applied research methodologies. Topics play a major role in providing insights into how participation in the doctoral research seminar.', ARRAY[]::TEXT[], NULL),
    ('SPEA-V 789', 'READINGS IN PUBLIC AFFAIRS', '12848', 'Class Status', NULL, NULL, 'Jennifer Silva', 10, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Readings on selected topics in public affairs.', ARRAY[]::TEXT[], NULL),
