    ('SPH-A 362', 'COACHING OF BASKETBALL', '5735', 'Class Status', 'TuTh Tuesday, Thursday 9:45 AM–10:35 AM', 'PH C100', 'Jonathan Campbell', 19, 'Lecture', 'Lecture', '2', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-A 362', 'COACHING OF BASKETBALL', '5736', 'Class Status', 'TuTh Tuesday, Thursday 8:40 AM–9:20 AM', 'GF 199', 'Jonathan Campbell', 17, 'Laboratory', 'Lecture', '2', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-A 362', 'COACHING OF BASKETBALL', '5737', 'Class Status', 'TuTh Tuesday, Thursday 10:50 AM–11:40 AM', 'GF 199', 'Jonathan Campbell', 2, 'Laboratory', 'Lecture', '2', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-A 483', 'PRINC OF SPORTS OFFICIATING', '1973', 'Class Status', 'W Wednesday 6:40 PM–9:10 PM', 'BH 106', 'Marcus Debro', 6, NULL, 'Lecture', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Topics include such sports as football, baseball, basketball, volleyball, and gymnastics. Ethics of sport officiating: mastery, interpretation, and application of sports rules. Laboratory and classroom experiences.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 510', 'EMERGENCY RESPONSE FOR THE ATHLETIC TRAINER', '8964', 'Class Status', NULL, NULL, 'Bradley Sage', 10, NULL, 'Lecture', '4', NULL, ARRAY[]::TEXT[], 'This course is designed to prepare the athletic trainer to evaluate and manage patient(s) with acute conditions that are life threatening or otherwise emergent.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 511', 'APPLIED CLINICAL PRACTICE IN ATHLETIC TRAINING I', '8965', 'Class Status', NULL, NULL, 'Joel Langemaat', 10, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'The first in a sequence of applied clinical skill courses this is designed to provide pertinent clinical skills and knowledge required in the athletic training profession. Specific skills include proper documentation and communication methods, interpretation of local, regional and national healthcare standards, statutes and regulations, the use of healthcare informatics.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 512', 'CRITICAL INQUIRY IN ATHLETIC HEALTHCARE I', '8966', 'Class Status', NULL, NULL, 'Bradley Sage', 10, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'The first in a sequence of critical inquiry courses this is designed to provide the athletic trainer with the skills necessary to locate, evaluate and apply evidence based practice from the healthcare literature to clinical practice.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 530', 'PRINCIPLES AND TECHNIQUES OF THERAPEUTIC INTERVENTION II', '9338', 'Class Status', NULL, 'HD TBA', 'Bradley Sage', 7, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course is the second of two sequential courses designed to provide the athletic trainer with the knowledge and skills required to develop, implement, and assess therapeutic interventions to meet the needs of patients. Students will be instructed on the proper use of therapeutic exercise, therapeutic modalities and manual therapies in the development, implementation and assessment of therapeutic interventions for the lower extremity.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 531', 'APPLIED CLINICAL PRACTICE IN ATHLETIC TRAINING III', '9336', 'Class Status', NULL, 'HD TBA', 'Joseph Lueken', 7, NULL, 'Lecture', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The third in a sequence of applied clinical skill courses designed to provide pertinent clinical skills and knowledge required in athletic training. Skill development for clinical decision making including referral but which includes proper use of appropriate screening tools to identify patients with behavioral health conditions.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 532', 'CRITICAL INQUIRY IN ATHLETIC HEALTHCARE III', '9337', 'Class Status', NULL, 'HD TBA', 'Bradley Sage', 7, NULL, 'Lecture', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The third in a sequence of critical inquiry courses this is designed to provide the skills necessary to locate, evaluate and apply evidence from the healthcare literature to clinical practice. Instruction in interpreting and applying evidence from scholarly literature in athletic healthcare to clinical practice will be developed.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 540', 'ORTHOPEDIC PRINCIPLES OF MSK INJURIES I', '9339', 'Class Status', NULL, 'HD TBA', 'Leif Madsen', 10, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course is the first of two sequential courses designed to provide the athletic trainer with the knowledge and skills related to diagnosis and management of musculoskeletal injuries.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 581', 'ATHLETIC TRAINING PRINCIPLES FOR THE SPINE', '10480', 'Class Status', NULL, 'HD TBA', 'Jackie Kingma', 7, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Advanced aspects of injury management with particular emphasis on philosophy of care for the athlete. Class lectures and discussion will focus on detailed assessment techniques and treatment of connective tissue, management of acute and chronic trauma to the spine and pelvis in sport. Particular emphasis will be placed on current research in prevention and treatment in physically active individuals.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 695', 'PRACTICUM IN ATHLETIC TRAINING', '9870', 'Class Status', NULL, NULL, 'Leif Madsen', 15, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Practical field experience in athletic training under supervision.', ARRAY[]::TEXT[], NULL),
    ('SPH-A 695', 'PRACTICUM IN ATHLETIC TRAINING', '14197', 'Class Status', NULL, NULL, 'Leif Madsen', 12, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Practical field experience in athletic training under supervision.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 150', 'INTRODUCTION TO PUBLIC HEALTH', '5919', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 310', 'Jingyi Wang', 16, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-B 150', 'INTRODUCTION TO PUBLIC HEALTH', '6336', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SW 119', 'Erin Cooperman', 18, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-B 150', 'INTRODUCTION TO PUBLIC HEALTH', '6341', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'RB 110', 'Angela Campbell', 49, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-B 150', 'INTRODUCTION TO PUBLIC HEALTH', '6357', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 310', 'Jingyi Wang', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-B 250', 'PUBLIC HEALTH COMMUNICATION', '9382', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 004', 'Erin Cooperman', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed specifically for those who will work largely in the field of public health including, but not limited to, students majoring in community health, dietetics, exercise science, and health education. This course provides the student with a general overview of the most important aspects of public health communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 250', 'PUBLIC HEALTH COMMUNICATION', '9512', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SE 105', 'Amaury de Siqueira', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed specifically for those who will work largely in the field of public health including, but not limited to, students majoring in community health, dietetics, exercise science, and health education. This course provides the student with a general overview of the most important aspects of public health communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 250', 'PUBLIC HEALTH COMMUNICATION', '11697', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–10:15 AM', 'WB WEB', 'Amaury de Siqueira', 11, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed specifically for those who will work largely in the field of public health including, but not limited to, students majoring in community health, dietetics, exercise science, and health education. This course provides the student with a general overview of the most important aspects of public health communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 250', 'PUBLIC HEALTH COMMUNICATION', '12286', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 004', 'Erin Cooperman', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed specifically for those who will work largely in the field of public health including, but not limited to, students majoring in community health, dietetics, exercise science, and health education. This course provides the student with a general overview of the most important aspects of public health communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 250', 'PUBLIC HEALTH COMMUNICATION', '34943', 'Closed', NULL, 'WB WEB', 'Heather Eastman-Mueller', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed specifically for those who will work largely in the field of public health including, but not limited to, students majoring in community health, dietetics, exercise science, and health education. This course provides the student with a general overview of the most important aspects of public health communication.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 310', 'PUBLIC HEALTH IN DIVERSE COMMUNITIES', '8817', 'Class Status', 'MW Monday, Wednesday 9:35 AM–12:05 PM', 'WB WEB', 'Wura Jacobs', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides the analytical tools to understand different health outcomes across diverse communities in the US. Explores how issues of culture, race, gender, and class influence health status and health behaviors. Uses case studies to examine the cultural, social, and economic aspects of health inequalities in the United States.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-B 310', 'PUBLIC HEALTH IN DIVERSE COMMUNITIES', '6208', 'Class Status', NULL, 'WB WEB', 'Kathy Finley', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides the analytical tools to understand different health outcomes across diverse communities in the US. Explores how issues of culture, race, gender, and class influence health status and health behaviors. Uses case studies to examine the cultural, social, and economic aspects of health inequalities in the United States.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-B 315', 'HEALTH IN THE LATER YEARS', '8820', 'Class Status', NULL, 'WB WEB', 'Jeanne Johnston', 21, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'As aging becomes a public health priority, an interdisciplinary consideration of the health issues of older adults is critical. This course reviews the biology of aging, health care, new research in aging, applications of integrative medicine for older adults, and physical activity and aging.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-B 350', 'SEMINAR IN PUBLIC HLTH EDUC', '30560', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SW 220', 'Carly Camplain', 28, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'The topical seminars will relate to current issues in the field of public health education. Possible topics for this seminar are aging, environmental health, teenage health problems, health problems of ethnic groups, public health administration, and group dynamics.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 354', 'AGING TODAY', '6287', 'Class Status', NULL, 'WB WEB', 'Ethan Hunt', 34, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is an overview of the areas involved in the study of aging. We will consider the major theoretical approaches and current research in aging in the following areas: biology and health, psychology, sociology, and social policy.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-B 360', 'PROFESSIONAL PATHWAYS IN COMMUNITY HEALTH', '30150', 'Class Status', 'Tu Tuesday 3:10 PM–6:10 PM', 'SB 131', 'Angela Taylor', 7, NULL, 'Lecture', '2', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Course is designed to assist junior and senior entry-level community health students prepare for entry level professions or graduate programs in the public health field. Explore career options, common graduate program application processes, and both hard and soft professional skills required in the public health field. Review required internship procedures.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 360', 'PROFESSIONAL PATHWAYS IN COMMUNITY HEALTH', '30153', 'Class Status', 'Th Thursday 3:10 PM–6:10 PM', 'WB WEB', 'Angela Taylor', 16, NULL, 'Lecture', '2', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Course is designed to assist junior and senior entry-level community health students prepare for entry level professions or graduate programs in the public health field. Explore career options, common graduate program application processes, and both hard and soft professional skills required in the public health field. Review required internship procedures.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 366', 'COMMUNITY HEALTH', '5857', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'RB 110', 'Travis Lawson', 31, NULL, 'Lecture', '3', 'STUDENT RECREATIONAL SPORTS CE', ARRAY[]::TEXT[], 'Introduction to community health within the public health context. Students will develop an understanding of historical and theoretical foundations of community health and major societal health concerns, explore community health models and programs used to address these concerns, and examine racial/ethnic, cultural, socioeconomical, and related determinants of community health.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 366', 'COMMUNITY HEALTH', '5856', 'Closed', NULL, 'WB WEB', 'Virginia Githiri', 0, NULL, 'Lecture', '3', 'STUDENT RECREATIONAL SPORTS CE', ARRAY[]::TEXT[], 'Introduction to community health within the public health context. Students will develop an understanding of historical and theoretical foundations of community health and major societal health concerns, explore community health models and programs used to address these concerns, and examine racial/ethnic, cultural, socioeconomical, and related determinants of community health.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 403', 'PUBLIC HEALTH PROGRAM PLANNING', '3166', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'SB 015', 'Heather Eastman-Mueller', 2, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Skill building in public health and health promotion program planning, including proposal presentations. Topics include program planning models, needs assessment methods, behavior change theories, types of community organization, social marketing principles, program implementation fundamentals, and evaluation techniques.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 496', 'BSPH PUBLIC HEALTH INTERNSHIP', '33687', 'Class Status', NULL, NULL, 'Kathy Finley', 41, NULL, 'Independent Study', '1–10', NULL, ARRAY[]::TEXT[], 'Field experience through on-the-job and related opportunities in public health. Students will be assigned to official, primary care, voluntary and related health agencies offering opportunities for professional development, practical application of skills, and participatory experience for the health educator. Regular critique will be held with supervisors and written progress reports are required.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 589', 'THEORIES AND CONCEPTUAL FRAMEWORKS IN PUBLIC HEALTH', '1974', 'Class Status', NULL, 'WB WEB', 'Kristen Jozkowski', 25, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Apply constructs and principles from individual, interpersonal, social, and organization theories and frameworks to understand and improve population health for diverse public health problems, populations and settings. Differentiate theories from conceptual frameworks. Develop diagram with causal pathways that is based on theory and scientific evidence.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 602', 'INTERVENTION DESIGN IN PUBLIC HEALTH', '5166', 'Class Status', 'Tu Tuesday 2:20 PM–3:35 PM', 'LH 328', 'Catherine Sherwood-Laughlin', 15, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Designing and selecting public health promotion interventions and programs which are grounded in theory, based on data, and appropriate to the setting and community. Emphasis on social and behavioral interventions.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 609', 'IMPLEMENTATION SCIENCE IN PUBLIC HEALTH', '29651', 'Class Status', 'Tu Tuesday 1:55 PM–3:25 PM', 'SY 137', 'Karla Galaviz', 5, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'The course introduces students to concepts and methods for implementation science. The course covers topics around identifying and appraising the evidence base, assessing, and addressing barriers that impede implementation of effective interventions, designing implementation strategies to Address such barriers, and evaluating those strategies.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 615', 'HEALTH, LONGEVITY AND INTEGRATIVE THERAPIES FOR THE LATER YEARS', '3638', 'Class Status', NULL, 'WB WEB', 'Jeanne Johnston', 48, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This interdisciplinary online course reviews health care, the biology of aging, new research in aging, and applications of integrative medicine for older adults. Students evaluate comparative effectiveness of integrative therapies and allopathic medicine for common chronic illnesses in the rapidly growing older adult population and critically analyze the "anti-aging" industry.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 630', 'SEXUAL AND REPRODUCTIVE HEALTH SURVEILLANCE', '9513', 'Class Status', 'Thirteen Week', 'WB WEB', 'William Yarber', 10, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In-depth orientation to the major methods and systems used for purposes of sexual and reproductive health surveillance, with a focus on the collection, analysis, and interpretation of data essential to planning, implementing, and evaluating efforts to promote sexual and reproductive health.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 634', 'SEXUAL HEALTH RESEARCH AND EVALUATION: METHODS AND APPROACHES', '8336', 'Class Status', NULL, 'WB WEB', 'Heather Eastman-Mueller', 19, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Sexual health scientists ask a range of unique questions which require tailored methods and approaches to answer. Through a combination of independent readings and interactive discussions, lectures and guest speakers, and student-led presentations, we will gain an understanding of the major elements of sexual health research, interventions, and practice.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 675', 'PRACTICUM IN PUBLIC HEALTH', '8337', 'Class Status', NULL, 'WB WEB', 'Catherine Sherwood-Laughlin', 10, NULL, 'Practicum', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Students pursuing a graduate degree in public health develop and apply knowledge and skills in appropriate professional settings. Practicum experiences must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 691', 'READINGS IN PUBLIC HEALTH', '5922', 'Class Status', NULL, NULL, 'Debra Herbenick', 14, NULL, 'Readings', '1–5', NULL, ARRAY[]::TEXT[], 'Planned readings in specialized areas of professional interest are conducted under the direction of a member of the graduate teaching faculty. Enrollment is limited to advanced graduate students, and reading proposals must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 692', 'RESEARCH IN PUBLIC HEALTH', '3124', 'Class Status', NULL, NULL, 'Carly Camplain', 14, NULL, 'Research', '1–5', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the graduate teaching faculty. Enrollment is limited to advanced graduate students, and project proposals must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 692', 'RESEARCH IN PUBLIC HEALTH', '5928', 'Class Status', NULL, NULL, 'Lucia Guerra Reyes', 13, NULL, 'Research', '1–5', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the graduate teaching faculty. Enrollment is limited to advanced graduate students, and project proposals must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 700', 'INTRODUCTION TO DOCTORAL STUDIES IN APPLIED HEALTH SCIENCE', '33773', 'Class Status', 'W Wednesday 9:00 AM–10:00 AM', 'SY 037', 'Jon Macy, Eric Walsh-Buhi', 11, NULL, 'Seminar', '1', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course introduces doctoral students to the basics of being a PhD student. Topics include the steps to earning your degree, expectations for PhD graduates entering the Academy, choosing a "professional home", grants and writing as a doctoral student, and diverse career pathways for PhD graduates.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 702', 'ADVANCED EVALUATION RESEARCH IN PUBLIC HEALTH', '5930', 'Class Status', 'Th Thursday 3:10 PM–5:40 PM', 'ED 3004', 'Brandon Crawford', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course provides students with advanced knowledge of and skills in evaluation research in public health program, policies and interventions. Topics include logic models, research designs, measurement, data collection, and advanced statistical and economic evaluation methods. This course is restricted to doctoral students and permission of instructor is required.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 710', 'METHODS FOR HEALTH BEHAVIOR RESEARCH', '33774', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:20 AM', 'BH 337', 'Jon Macy', 12, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course is a doctoral level overview of methods used in health behavior research. The goal is to provide a foundation of knowledge before PhD students move to more sophisticated doctoral research courses, start to work with faculty on research projects, and initiate their own independent research projects.', ARRAY[]::TEXT[], NULL),
    ('SPH-B 784', 'ADVANCED SEM IN PUB HLTH', '12951', 'Class Status', 'Thirteen Week', NULL, 'Alyssa Lederer', 13, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Advanced topics in the area of public health are studied under the direction of faculty members with specialized areas of expertise. Specific topics vary.', ARRAY[]::TEXT[], NULL),
    ('SPH-C 213', 'INTRODUCTION TO SPORT COMMUNICATION', '11412', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'LU 1001', 'Sinhae Roh', 0, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'An introduction to the area of sport communication. Emphasis is placed on the fields within sport communication, including, but not limited to: sport information, public relations, media relations, player relations, radio and TV sports production, marketing and research, interactive media, media trends, production competencies, and employment options and trends.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-C 213', 'INTRODUCTION TO SPORT COMMUNICATION', '9798', 'Closed', NULL, 'WB WEB', 'Paul Pedersen', 0, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'An introduction to the area of sport communication. Emphasis is placed on the fields within sport communication, including, but not limited to: sport information, public relations, media relations, player relations, radio and TV sports production, marketing and research, interactive media, media trends, production competencies, and employment options and trends.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-C 213', 'INTRODUCTION TO SPORT COMMUNICATION', '32691', 'Closed', NULL, 'WB WEB', 'Paul Pedersen', 0, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'An introduction to the area of sport communication. Emphasis is placed on the fields within sport communication, including, but not limited to: sport information, public relations, media relations, player relations, radio and TV sports production, marketing and research, interactive media, media trends, production competencies, and employment options and trends.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-C 329', 'ISSUES IN SPORT COMMUNICATION', '8674', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'RB 110', 'Jonathan Benedek', 0, NULL, 'Lecture', '3', 'STUDENT RECREATIONAL SPORTS CE', ARRAY[]::TEXT[], 'Examines issues in sport communication utilizing extensive student participation in case scenarios, role playing, and sport communication profiles. Special attention is given to topics including: historical and theoretical features of the field, personal and organizational processes, sport media, services and support systems, sociological and legal aspects.', ARRAY[]::TEXT[], NULL),
    ('SPH-C 580', 'SPORT COMMUNICATIONS', '9845', 'Closed', NULL, NULL, 'Paul Pedersen', 0, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-E 250', 'PUBLIC HEALTH SURVEILLANCE AND MONITORING', '10342', 'Closed', NULL, 'WB WEB', 'Vickie VanDeventer', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The CDC describes disease surveillance and monitoring as "the systematic collection, analysis, interpretation, and dissemination of data for use in prioritizing, planning, implementing, and evaluating health programs, activities, and practices". The disease surveillance and monitoring is one of the fundamental activities of Public Health in the United States and other developed, developing countries, and represents the primary source of information about the health of a population. This course will focus on the fundamental processes and procedures to investigate and track infectious and communicable diseases as well as non-infectious chronic diseases.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-E 311', 'INTRODUCTION TO EPIDEMIOLOGY', '3243', 'Closed', NULL, 'WB WEB', 'Erik Nelson', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Epidemiology concepts, measures, and methods are introduced and applied to explain major health problems, their risks factors, processes, and changes in specific populations. Application of epidemiological methods to identification, surveillance, prevention, and disease control in individuals, families, and communities are addressed.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 350', 'INFECTIOUS DISEASES: OUTBREAKS AND FIELD INVESTIGATIONS', '9335', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 1118', 'Andre Wilke', 17, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Students will learn the history and the basic methods of investigation, study the epidemiology, and examine case studies of important, new and emerging diseases and syndromes that affect human populations. Instruction includes definitions and nomenclature, outbreak investigation processes and procedures, disease surveillance and monitoring, and prevention and control efforts. Case-studies focus on acute respiratory infections, diarrheal diseases, hepatitis, tuberculosis, HIV, sexually transmitted infections, malaria, and other vector-borne diseases.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 353', 'DISTRIBUTION AND DETERMINANTS OF CHRONIC DISEASES', '11551', 'Class Status', NULL, 'WB WEB', 'Vickie VanDeventer', 18, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will provide an introduction to chronic disease epidemiology. The course will discuss the pathogenesis and population distribution of some of the major chronic diseases that affect health (e.g. cardiovascular disease, diabetes, cancer). Additionally, students will learn about the major risk factors for chronic disease and strategies for population-based prevention. Finally, students will get an introduction to basic methods for ascertaining exposures and outcomes as well as research designs for studying chronic diseases.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 358', 'EPIDEMIOLOGIC METHODS: CONCEPTS', '9171', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WB WEB', 'Moriah Harton', 27, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will build upon the concepts introduced in Introduction to Epidemiology by going into further detail regarding elements of study design, data analysis, and interpretation of results. Students will learn the basic methods utilized in epidemiology and how to apply them to public health. The course is also intended to provide an introduction to the basic skills needed to critically evaluate the epidemiologic literature relevant to public health professionals.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 358', 'EPIDEMIOLOGIC METHODS: CONCEPTS', '10843', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WB WEB', 'Moriah Harton', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will build upon the concepts introduced in Introduction to Epidemiology by going into further detail regarding elements of study design, data analysis, and interpretation of results. Students will learn the basic methods utilized in epidemiology and how to apply them to public health. The course is also intended to provide an introduction to the basic skills needed to critically evaluate the epidemiologic literature relevant to public health professionals.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 359', 'EPIDEMIOLOGIC METHODS: APPLICATIONS', '10804', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WY 101', 'Christina Ludema', 23, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'The course covers applications of epidemiologic methods and procedures to the study of the distribution and determinants of health outcomes including disease risk, morbidity, injuries, disability, mortality in populations, and health disparities. Other topics include quantitative aspects of epidemiology, for example, data sources, measures of morbidity and mortality, evaluation of association and causality, and study design.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 451', 'ETHICS AND EXPLOITATION: MEDICAL MISTRUST AND MISTREATMENT IN PUBLIC HEALTH', '15082', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'WB WEB', 'Rory James', 13, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on bioethics in public health practice and research with an emphasis on bioethical analyses of historical abuses in scientific inquiry and research; current policies and procedures in public health, law enforcement, and technology; and the role of race, gender, and identity in research, epidemiology, and healthcare practice.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 496', 'FIELD EXPERIENCE IN EPIDEMIOLOGY', '8452', 'Class Status', NULL, NULL, 'Kathy Finley', 19, NULL, 'Internship', '1–10', NULL, ARRAY[]::TEXT[], 'BSPH students in the Epidemiology concentration develop their public health skills through professional experiences in public health settings under the supervision of IU SPH-B faculty and facilitation of preceptors. The Faculty Coordinator and the preceptors conduct regular evaluations, provide written progress reports, and facilitate the development of the Major Independent Project.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 651', 'EPIDEMIOLOGY', '11862', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WB WEB', 'Juhua Luo', 31, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Epidemiology, public health''s basic science, supports health monitoring, etiologic studies, intervention design and evaluation, and health policy. Health measures exercises use public data, and simulation. In a final proposal students apply epidemiologic principals to evaluate current literature, develop appropriate study design and methods, and strategies to limit threats to validity.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 653', 'CHRONIC DISEASE EPIDEMIOLOGY', '10341', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WY 125', 'Aurelian Bidulescu', 29, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'An overview of concepts in chronic disease epidemiology and etiology; study design in epidemiologic research and causal inference; major chronic diseases and trends in both the U.S. and world-wide; prevention, and screening.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 653', 'CHRONIC DISEASE EPIDEMIOLOGY', '11864', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Aurelian Bidulescu', 8, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'An overview of concepts in chronic disease epidemiology and etiology; study design in epidemiologic research and causal inference; major chronic diseases and trends in both the U.S. and world-wide; prevention, and screening.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 657', 'SOCIAL EPIDEMIOLOGY', '12042', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SY 0013', 'Molly Rosenberg', 15, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Introduction to social epidemiology, including methods and key study findings of how social factors affect health outcomes. Topics include the role of socioeconomic status, race, gender, neighborhoods, work place, and social networks, and upstream determinants such as social capital, income inequality and social policies on health.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 657', 'SOCIAL EPIDEMIOLOGY', '12741', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WB WEB', 'Molly Rosenberg', 26, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Introduction to social epidemiology, including methods and key study findings of how social factors affect health outcomes. Topics include the role of socioeconomic status, race, gender, neighborhoods, work place, and social networks, and upstream determinants such as social capital, income inequality and social policies on health.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 680', 'NUTRITIONAL EPIDEMIOLOGY', '12607', 'Class Status', 'W Wednesday 11:15 AM–12:30 PM', 'WB WEB', 'Ines Gonzalez Casanova', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course introduces basic concepts of epidemiology, basic methods of dietary assessment, reviews various topics in nutrition and chronic diseases and teaches the skills needed for critical evaluation of the nutrition epidemiology literature.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 758', 'ADVANCED EPIDEMIOLOGY', '10802', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PY 113', 'Christina Ludema', 6, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Causal inference from observational data is a key task of epidemiology. This course presents the concepts underlying causal theory and then shows how epidemiologic methods can be understood within this framework. Epidemiologic concepts such as confounding, overall effects, and bias will be formally defined within the context of counterfactual theory.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 759', 'ADVANCED EPIDEMIOLOGICAL METHODS', '7530', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 015', 'Ming Li', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course will present advanced statistical methods used in Epidemiology. Topics that will be covered include: - Marginal Effects and Potential Outcomes Estimation - Propensity Scores - Analysis of Time-Dependent Treatments - Cox-Proportional Hazards Model - Longitudinal and Hierarchical Data Analysis - Generalized Estimating Equations - GLMs and GAMs', ARRAY[]::TEXT[], NULL),
    ('SPH-E 792', 'INDEPENDENT RESEARCH IN EPIDEMIOLOGY', '35242', 'Class Status', 'Tu Tuesday 9:35 AM–10:50 AM', 'BH 018', 'Corey Kalbaugh', 5, NULL, 'Research', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Research project is conducted under the direction of faculty member of the graduate faculty. This can be in form of grant writing, or manuscript preparation, or data analysis. Enrollment is limited to advanced graduate students, and project proposals must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 792', 'INDEPENDENT RESEARCH IN EPIDEMIOLOGY', '6115', 'Class Status', NULL, NULL, 'Aurelian Bidulescu', 4, NULL, 'Research', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Research project is conducted under the direction of faculty member of the graduate faculty. This can be in form of grant writing, or manuscript preparation, or data analysis. Enrollment is limited to advanced graduate students, and project proposals must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 793', 'INDEPENDENT READINGS IN EPIDEMIOLOGY', '37190', 'Class Status', NULL, NULL, 'Maria Litvinova', 4, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Planned readings in specialized epidemiology areas of professional interest are conducted under the direction of a member of the graduate faculty. Enrollment is limited to advanced graduate students, and reading proposals must be approved in advance.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 794', 'DOCTORAL SEMINAR IN EPIDEMIOLOGY', '9999', 'Class Status', 'F Friday 12:45 PM–2:45 PM', 'WH 111', 'Carmen Tekwe', 50, NULL, 'Lecture', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course will equip students with skills to apply epidemiological concepts to critically evaluate research reports in the public health and medical literature. Students will have opportunities to lead discussions, and present their proposed dissertation studies. The class will invite guest speakers to present their research relevant to epidemiology and public health.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 799', 'DISSERTAION RESEARCH IN EPIDEMIOLOGY', '5994', 'Class Status', NULL, NULL, 'Corey Kalbaugh', 8, NULL, 'Research', '1–12', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This provides an environment for mentored research designed to answer the doctoral candidate''s research question. The credit hours are meant to be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
    ('SPH-E 799', 'DISSERTAION RESEARCH IN EPIDEMIOLOGY', '5995', 'Class Status', NULL, NULL, 'Juhua Luo', 9, NULL, 'Research', '1–12', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This provides an environment for mentored research designed to answer the doctoral candidate''s research question. The credit hours are meant to be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
