    ('SPH-F 180', 'INTRODUCTION TO CHILD AND YOUTH WORK', '9470', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SE 105', 'Jessica McKinley', 26, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'This course prepares students for the professional practice of serving youth and families in public, health, education, recreation and social settings. Course concepts include youth and family services delivery settings, theoretical frameworks related to youth services, and professional ethics, organizations, and credentialing. This course includes a service learning component.', ARRAY[]::TEXT[], NULL),
