    ('SPH-F 258', 'THE TIES THAT BIND: RELATIONSHIPS, MARRIAGE, AND THE FAMILY', '5719', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 203', 'Emma Willis-Grossmann', 40, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This an applied course, designed to help students explore the many facets of relationships, marriages and families. The primary focus: the ways in which your experience of family has affected, is affecting and will affect you in the future, and will examine this subject from a personal and scholarly perspective.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-F 258', 'THE TIES THAT BIND: RELATIONSHIPS, MARRIAGE, AND THE FAMILY', '7536', 'Class Status', 'MW Monday, Wednesday 3:10 PM–5:40 PM', 'BH 227', 'Angela Taylor', 35, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This an applied course, designed to help students explore the many facets of relationships, marriages and families. The primary focus: the ways in which your experience of family has affected, is affecting and will affect you in the future, and will examine this subject from a personal and scholarly perspective.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-F 345', 'PARENTS, PARENTING, & CHILDREN', '4436', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TV 245', 'Angie Wong', 26, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Explores issues associated with parenting and addresses the reciprocal processes and interdependencies among parents, children, and their multiple environments.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 346', 'THE PRENATAL PERIOD THROUGH EARLY CHILDHOOD - HUMAN DEVELOPMENT I', '1980', 'Class Status', NULL, 'WB WEB', 'Angie Wong', 17, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examination of prenatal, infant, preschool development; physical, cognitive, and social-emotional characteristics of development.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 346', 'THE PRENATAL PERIOD THROUGH EARLY CHILDHOOD - HUMAN DEVELOPMENT I', '10107', 'Class Status', NULL, 'WB WEB', 'Angie Wong', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examination of prenatal, infant, preschool development; physical, cognitive, and social-emotional characteristics of development.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 347', 'MIDDLE CHILDHOOD THROUGH ADOLESCENCE - HUMAN DEVELOPMENT II', '5611', 'Class Status', 'Thirteen Week', 'WB WEB', 'Angela Chow', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines human development during the school years, or middle childhood, through adolescence. Addresses major concepts and issues concerning development, in the physical, cognitive, psychological, and social domains.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-F 410', 'THE SCIENCE OF POSITIVE YOUTH DEVELOPMENT', '9469', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WB WEB', 'Rebecca Gilbert', 9, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Positive Youth Development (PYD) focuses on improving competence, confidence, character, connection, and caring among youth. Students will learn the origins of PYD, how its principles are applied in the development of youth focused programs, and review research on how PYD impacts youth.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 410', 'THE SCIENCE OF POSITIVE YOUTH DEVELOPMENT', '12791', 'Closed', NULL, 'WB WEB', 'Stephanie Turpin', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Positive Youth Development (PYD) focuses on improving competence, confidence, character, connection, and caring among youth. Students will learn the origins of PYD, how its principles are applied in the development of youth focused programs, and review research on how PYD impacts youth.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 417', 'AFRICAN AMERICAN AND LATINO FAMILIES', '8458', 'Class Status', 'Thirteen Week', 'WB WEB', 'Maresa Murray', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Enacts a strength-based approach in the examination of African American and Latino family structure in a socio-historical context with emphasis on cultural resiliency. Current statistics, scholarly literature, and American media segments will be used to illustrate aspects of cultural perception.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 430', 'PROFESSIONAL PREPARATION IN HUMAN DEVELOPMENT AND FAMILY STUDIES', '6466', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'ED 2101', 'Angie Wong', 12, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Exploration of professional roles and career opportunities in HDFS. Addresses necessary skills and information related to the search for employment and/or graduate school.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 453', 'FAMILY LIFE EDUCATION', '1982', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SY 037', 'Alison Greene', 13, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'History of family life education; philosophy and rationale for curriculum development, including methods and source materials. Current methods and theory provide the basis for program planning relevant to contemporary developmental and family issues.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 457', 'PROTECTIVE FACTORS, RESILIENCE, AND STRESS IN THE FAMILY', '5396', 'Class Status', 'Thirteen Week', 'WB WEB', 'Maresa Murray', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Research and theory on family stress and resilience. Addresses important aspects of the family''s experience of stress, (e.g., as social support and coping in a family context) as well as resilience factors that reduce the effects of stress on families.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 458', 'FAMILY LAW AND POLICY', '7055', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1128', 'Erin Cooperman', 17, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course is an overview of the family law and policy issues in the United States. The class is organized around the four major disciplines that shape how policy is formed, evaluated, and implemented: political science, economics, sociology, and science. Each module will include lectures to introduce core concepts and analytical tools, case studies, and films. The final section of class will explore current family law and policy issues.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 458', 'FAMILY LAW AND POLICY', '9384', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1128', 'Erin Cooperman', 8, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course is an overview of the family law and policy issues in the United States. The class is organized around the four major disciplines that shape how policy is formed, evaluated, and implemented: political science, economics, sociology, and science. Each module will include lectures to introduce core concepts and analytical tools, case studies, and films. The final section of class will explore current family law and policy issues.', ARRAY[]::TEXT[], NULL),
    ('SPH-F 497', 'INTERNSHIP IN HUMAN DEVELOPMENT AND FAMILY STUDIES', '11501', 'Class Status', NULL, NULL, 'Jennifer Engels', 58, NULL, 'Independent Study', '6', NULL, ARRAY[]::TEXT[], 'HDFS development course that corresponds to age group with which student will work; authorization of HDFS faculty supervisor. Involves active participation in community programs.', ARRAY[]::TEXT[], NULL),
    ('SPH-G 599', 'THESIS RESEARCH', '3137', 'Class Status', NULL, NULL, 'Jon Macy', 10, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('SPH-G 901', 'ADVANCED RESEARCH', '1983', 'Class Status', NULL, NULL, 'Jon Macy', 35, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 150', 'CHILDREN''S HEALTH UP TO AGE 5', '10105', 'Class Status', NULL, 'WB WEB', 'Cecilia Obeng', 90, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course focuses on recent research on infant feeding and sleeping needs. Causes, prevention and management of the health and safety problems of pre-school aged children are presented. Emphasis is on health and social service agencies.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 150', 'CHILDREN''S HEALTH UP TO AGE 5', '5590', 'Closed', NULL, 'WB WEB', 'Cecilia Obeng', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course focuses on recent research on infant feeding and sleeping needs. Causes, prevention and management of the health and safety problems of pre-school aged children are presented. Emphasis is on health and social service agencies.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 160', 'FIRST AID AND EMERGENCY CARE', '14494', 'Class Status', 'M Monday 11:35 AM–12:25 PM', 'MO 007', 'Coy Timbrook', 62, 'Lecture', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Course addresses cardiopulmonary resuscitation (CPR), rescue breathing, choking, wounds, bleeding, burns, sudden illnesses, musculoskeletal injuries, and defibrillation/ the use of Automated External Defibrillators (AEDs). Skills are practiced in small lab settings. Students have the opportunity to gain professional certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 160', 'FIRST AID AND EMERGENCY CARE', '14495', 'Class Status', 'MW Monday, Wednesday 10:20 AM–11:10 AM', 'PH 021', 'Coy Timbrook', 6, 'Laboratory', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Course addresses cardiopulmonary resuscitation (CPR), rescue breathing, choking, wounds, bleeding, burns, sudden illnesses, musculoskeletal injuries, and defibrillation/ the use of Automated External Defibrillators (AEDs). Skills are practiced in small lab settings. Students have the opportunity to gain professional certification.', ARRAY[]::TEXT[], NULL),
