    ('SPH-H 160', 'FIRST AID AND EMERGENCY CARE', '14503', 'Class Status', 'TuTh Tuesday, Thursday 11:30 AM–12:20 PM', 'PH 021', 'Coy Timbrook', 7, 'Laboratory', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Course addresses cardiopulmonary resuscitation (CPR), rescue breathing, choking, wounds, bleeding, burns, sudden illnesses, musculoskeletal injuries, and defibrillation/ the use of Automated External Defibrillators (AEDs). Skills are practiced in small lab settings. Students have the opportunity to gain professional certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 170', 'HEALTH THROUGH THE COLLEGE YEARS', '1984', 'Class Status', NULL, 'WB WEB', 'Kathy Finley', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers the health and wellness issues related to a student''s transition from high school to college. It focuses on education and prevention issues and includes the following topics: stress, sexuality, safety, substance use and abuse, fitness, nutrition, budgeting, and emotional health.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 172', 'INTL HEALTH & SOCIAL ISSUES', '1985', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 310', 'Julia Sherry', 46, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Covers world health problems and efforts being made to achieve optimal health for all. Exposes students to health concerns of non-Western and nondominant cultures. Population dynamics, vital statistics, global disease patterns, and analysis of variations among nations will be considered in analyzing health status of people and communities around the world.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-H 174', 'PREV OF VIOLENCE IN AMER SOC', '5694', 'Class Status', 'MW Monday, Wednesday 3:10 PM–5:40 PM', 'GY 1043', 'Ganghui Suh', 25, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course covers various contributors to violence in America with an emphasis on community health issues. Personal and environmental factors related to violence are considered within a context of public health. Personal and community violence prevention and reduction approaches are presented.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-H 174', 'PREV OF VIOLENCE IN AMER SOC', '5693', 'Closed', NULL, 'WB WEB', 'Rashad Freeman', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course covers various contributors to violence in America with an emphasis on community health issues. Personal and environmental factors related to violence are considered within a context of public health. Personal and community violence prevention and reduction approaches are presented.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-H 180', 'STRESS PREVENTION & MANAGEMENT', '5695', 'Class Status', 'MW Monday, Wednesday 1:55 PM–4:25 PM', 'GA 1118', 'Jeffrey Grant', 31, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course is designed to help students learn about the body''s reaction to perceived stress, mental and physical factors related to stress, and effective coping techniques to help mitigate causes of stress. Students may acquire several stress management techniques that include diaphragmatic breathing, visualization, meditation, and progressive muscular relaxation.', ARRAY['Class uses IU eTexts'], NULL),
