    ('SPH-H 220', 'DEATH & DYING', '3165', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'OP 105', 'Jeremy Voyles', 74, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introductory analysis of the dying and death experience with emphasis on the development of a healthy personal death awareness. Topics include processes of dying, needs and care of the dying person, grief, legal and consumer aspects, and children and death.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-H 263', 'PERSONAL HEALTH', '5699', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'WH 004', 'Rebecca Mueller', 24, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This survey course provides a theoretical and practical treatment of the concepts of disease prevention and health promotion. Covers such topics as emotional health; aging and death; alcohol, tobacco, and drug use disorders; physical fitness; nutrition and dieting; consumer health; chronic and communicable diseases; safety; and environmental health.', ARRAY['IUB GenEd S&H credit
