    ('SPH-H 305', 'WOMEN''S HEALTH', '5704', 'Class Status', 'MW Monday, Wednesday 3:10 PM–5:40 PM', 'SY 103', 'Rachel Boveja', 3, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course is designed to provide students with an opportunity to examine the relationship of women to health and health care. Five dimensions of health: physical, mental, emotional, social, and spiritual provide a framework for comparison and contrast of health concerns unique to women and common to both sexes at all ages.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 305', 'WOMEN''S HEALTH', '5705', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 1112', 'Angela De Leon', 18, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course is designed to provide students with an opportunity to examine the relationship of women to health and health care. Five dimensions of health: physical, mental, emotional, social, and spiritual provide a framework for comparison and contrast of health concerns unique to women and common to both sexes at all ages.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 306', 'MEN''S HEALTH', '1986', 'Class Status', 'TuTh Tuesday, Thursday 3:10 PM–5:40 PM', 'LI 503', 'Alexandra Cottingham', 20, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'This course provides an overview of male health issues. Course topics include gender as a factor in men''s health behavior and risks, the way men perceive and use their bodies, and men''s psychological experience of health, wellness, and illness.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 306', 'MEN''S HEALTH', '1987', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WH 109', 'Craig Barnhart', 19, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'This course provides an overview of male health issues. Course topics include gender as a factor in men''s health behavior and risks, the way men perceive and use their bodies, and men''s psychological experience of health, wellness, and illness.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 312', 'COVID-19: IMPLICATIONS ON MATERNAL AND CHILD HEALTH POPULATION', '11978', 'Class Status', NULL, 'WB WEB', 'Amy Meek', 46, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course introduces students to recent research and practice on COVID-19 and its implications for Maternal and Child Health populations. Information on existing and emerging health related problems brought about by COVID-19 are presented and elucidated. Agencies involved in the fight against the COVID-19 pandemic are also identified and discussed.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 318', 'DRUG USE IN AMERICAN SOCIETY', '5706', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 203', 'Kathy Finley', 43, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An interdisciplinary approach to the study of drug use in American society. The course will examine the effects of alcohol, tobacco, and the "illicit'''' drugs on the physical, mental, and social health of the individuals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 318', 'DRUG USE IN AMERICAN SOCIETY', '9386', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 203', 'Kathy Finley', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An interdisciplinary approach to the study of drug use in American society. The course will examine the effects of alcohol, tobacco, and the "illicit'''' drugs on the physical, mental, and social health of the individuals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 318', 'DRUG USE IN AMERICAN SOCIETY', '5708', 'Closed', NULL, 'WB WEB', 'Amy Frederick', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An interdisciplinary approach to the study of drug use in American society. The course will examine the effects of alcohol, tobacco, and the "illicit'''' drugs on the physical, mental, and social health of the individuals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 318', 'DRUG USE IN AMERICAN SOCIETY', '6358', 'Closed', NULL, 'WB WEB', 'Amy Frederick', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An interdisciplinary approach to the study of drug use in American society. The course will examine the effects of alcohol, tobacco, and the "illicit'''' drugs on the physical, mental, and social health of the individuals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 319', 'GLOBAL HEALTH PROMOTION', '8923', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WY 115', 'Julia Sherry', 34, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course examines the combination of behavioral, social, economic, and environmental factors that influence health and enables students to develop knowledge and skills they can use throughout their lives to protect and improve their own health, the health of their families, and health of communities in which they will live.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 320', 'THE NATURE OF CANCER', '1988', 'Closed', NULL, 'WB WEB', 'Virginia Githiri', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course deals mainly with primary and secondary prevention of cancer. Various topics include lifestyle and cancer, causes of cancer, types of cancer, methods of detecting cancer, methods of treating cancer, and public attitudes. Discusses economic and psychological problems involved with cancer.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 334', 'HEART HEALTH AND DIABETES', '37557', 'Class Status', 'TuTh Tuesday, Thursday 3:10 PM–5:40 PM', 'SY 006', 'Sixtus Aguree', 5, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Heart disease is the leading cause of death for both men and women. Examined are preventive individual lifestyle and public health intervention resources addressing knowledge and skills related to risk factors of tobacco use, diet/obesity, physical inactivity, hypertension and diabetes.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 350', 'TOPICAL SEMINAR IN HEALTH PROMOTION', '14864', 'Class Status', NULL, 'WB WEB', 'Maresa Murray', 18, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The topical seminars will relate to current issues in the field of health promotion and education. Repeatable for credit with different topic.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 350', 'TOPICAL SEMINAR IN HEALTH PROMOTION', '37249', 'Closed', NULL, 'WB WEB', 'Virginia Githiri', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The topical seminars will relate to current issues in the field of health promotion and education. Repeatable for credit with different topic.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 351', 'COMPLEMENTARY/ALT APPR TO HLTH', '5709', 'Class Status', 'W Wednesday 4:55 PM–7:25 PM', 'LH 004', 'Roberta (Bobbie) Saccone', 12, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course discusses traditional health practices used as primary health care by 65 to 85 percent of the world''s population. Discussion and activities will center on enhancing awareness of complementary and alternative practices such as acupressure, acupuncture, aromatherapy, biomagnetic applications, chiropractics, herbology/botanicals, homeopathy, meditation, and naturopathy.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 360', 'WRITING IN PUBLIC HEALTH', '12303', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WH 005', 'Danny Valdez', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This writing-intensive course will relate to writing principles, elementary research strategies, and 21st century health literacy for a public health audience.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 360', 'WRITING IN PUBLIC HEALTH', '12302', 'Closed', NULL, 'WB WEB', 'Danny Valdez', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This writing-intensive course will relate to writing principles, elementary research strategies, and 21st century health literacy for a public health audience.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 360', 'WRITING IN PUBLIC HEALTH', '14791', 'Closed', NULL, 'WB WEB', 'Wura Jacobs', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This writing-intensive course will relate to writing principles, elementary research strategies, and 21st century health literacy for a public health audience.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 360', 'WRITING IN PUBLIC HEALTH', '34903', 'Closed', NULL, 'WB WEB', 'Christine Tisone', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This writing-intensive course will relate to writing principles, elementary research strategies, and 21st century health literacy for a public health audience.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 380', 'MATERNAL AND CHILD HEALTH', '11504', 'Class Status', NULL, 'WB WEB', 'Temitope Erinosho', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course introduces students to Maternal and Child Health (MCH) field. It is taught in such a way that it will enable students to assess existing and emerging health related needs of the MCH population and develop strategies to deal with them.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 395', 'PRACTICUM IN SEXUAL AND REPRODUCTIVE HEALTH EDUCATION', '6971', 'Class Status', NULL, 'WB WEB', 'Heather Eastman-Mueller', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examination of sexuality education strategies and leading group discussions for SPH-F 255 Human Sexuality.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 401', 'EMERGENCY MED TECHN AMBUL I', '5398', 'Class Status', 'Tu Tuesday 5:10 PM–8:10 PM', 'LH 130', 'Anmar Mirza', 3, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Must take concurrently with SPH-H 404 EMT Lab. This class prepares the students to care for patients in a variety of emergency settings. In order to take the Indiana State EMT Certification exam, students must complete this course and SPH-H 404 and be at least 18 years of age.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 403', 'EMERGENCY MED TECH TCHNG ASST', '1989', 'Class Status', NULL, NULL, 'Anmar Mirza', 18, NULL, 'Lecture', '1–2', NULL, ARRAY[]::TEXT[], 'This course is directed toward the instruction of emergency medical technician skills. The student comes to class with EMT training and provides skills assistance to EMT students.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 404', 'EMERGENCY MEDICAL TECHNICIAN LAB', '3095', 'Class Status', 'F Friday 9:00 AM–12:00 PM', 'PH 021', 'Anmar Mirza', 23, NULL, 'Laboratory', '1', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], 'The EMT Lab teaches skills necessary to care for patients in the prehospital setting. It includes automated defibrillation, airway adjuncts, oxygen delivery, managing wounds, and other procedures. Students complete evaluations under the instruction of certified EMTs. Meets the Department of Transportation and Public Safety Institute standards.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 404', 'EMERGENCY MEDICAL TECHNICIAN LAB', '3096', 'Class Status', 'F Friday 12:00 PM–3:00 PM', 'PH 021', 'Anmar Mirza', 21, NULL, 'Laboratory', '1', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], 'The EMT Lab teaches skills necessary to care for patients in the prehospital setting. It includes automated defibrillation, airway adjuncts, oxygen delivery, managing wounds, and other procedures. Students complete evaluations under the instruction of certified EMTs. Meets the Department of Transportation and Public Safety Institute standards.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 404', 'EMERGENCY MEDICAL TECHNICIAN LAB', '5399', 'Class Status', 'Th Thursday 6:00 PM–9:00 PM', 'PH 021', 'Anmar Mirza', 7, NULL, 'Laboratory', '1', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], 'The EMT Lab teaches skills necessary to care for patients in the prehospital setting. It includes automated defibrillation, airway adjuncts, oxygen delivery, managing wounds, and other procedures. Students complete evaluations under the instruction of certified EMTs. Meets the Department of Transportation and Public Safety Institute standards.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 419', 'PRINCIPLES OF SUBSTANCE ABUSE ASSESSMENT AND TREATMENT', '10829', 'Class Status', NULL, 'WB WEB', 'Katharine Sadler', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Intended to introduce students to evidence-based practices (EBP) in SBIRT, assessment, and treatment that can identify and effectively intervene with those who are at moderate or high risk from substance use', ARRAY[]::TEXT[], NULL),
    ('SPH-H 419', 'PRINCIPLES OF SUBSTANCE ABUSE ASSESSMENT AND TREATMENT', '10830', 'Class Status', NULL, 'WB WEB', 'Katharine Sadler', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Intended to introduce students to evidence-based practices (EBP) in SBIRT, assessment, and treatment that can identify and effectively intervene with those who are at moderate or high risk from substance use', ARRAY[]::TEXT[], NULL),
    ('SPH-H 494', 'RESEARCH AND EVALUATION METHODS IN PUBLIC HEALTH', '5400', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 1106', 'William Yarber', 10, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course deals with general concepts and foundations of measurement, evaluation, and research. Additionally the course covers major methods and techniques of research and evaluation. Special emphasis is given to writing small research and grant proposals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 494', 'RESEARCH AND EVALUATION METHODS IN PUBLIC HEALTH', '6209', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WY 101', 'Alyssa Lederer', 13, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course deals with general concepts and foundations of measurement, evaluation, and research. Additionally the course covers major methods and techniques of research and evaluation. Special emphasis is given to writing small research and grant proposals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 494', 'RESEARCH AND EVALUATION METHODS IN PUBLIC HEALTH', '10764', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WB WEB', 'Jingyi Wang', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course deals with general concepts and foundations of measurement, evaluation, and research. Additionally the course covers major methods and techniques of research and evaluation. Special emphasis is given to writing small research and grant proposals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 512', 'COVID-19: IMPLICATIONS ON MATERNAL AND CHILD HEALTH POPULATION', '11979', 'Class Status', NULL, 'WB WEB', 'Amy Meek', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course introduces students to recent research and practice on COVID-19 and its implications on Maternal and Child Health (MCH). Research on prevention and safety issues on COVID-19 are presented. Agencies involved in the fight against the COVID-19 pandemic are discussed. Emphasis is on health education for the MCH populations.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 518', 'ALCOHOL & DRUG EDUCATION', '6207', 'Closed', NULL, 'WB WEB', 'Amy Frederick', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Alcohol and drug use disorders in American society are probed in a comprehensive yet practical manner. Physiological, psychological, sociological, theological, and legal dimensions of the issue are explored through lectures, group discussions, guest speakers, and audio-visual presentations. Discusses principles of teaching and counseling in drug education programs.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 580', 'FOUNDATIONAL ISSUES IN MATERNAL AND CHILD HEALTH', '11560', 'Class Status', NULL, 'WB WEB', 'Temitope Erinosho', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to train Maternal and Child Health (MCH) leaders to acquire knowledge, important skills in technology, and professional competence that will enable them to assess and deal with MCH-related needs and issues.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-H 595', 'PRACTICUM IN SEXUAL AND REPRODUCTIVE HEALTH EDUCATION', '6972', 'Class Status', NULL, 'WB WEB', 'Heather Eastman-Mueller', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Includes the study of sexuality education methodology, preparation of learning activities dealing with human sexuality, evaluation of student papers, and leading discussion sections of SPH-F 255 Human Sexuality.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 650', 'SEMINAR IN HEALTH PROMOTION', '12469', 'Class Status', NULL, NULL, 'Heather Eastman-Mueller', 8, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Contemporary topics in health promotion and education are studied under the direction of faculty members with specialized areas of expertise. Specific topics vary.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 662', 'ACQUIRING & MANAGING EXTERNAL FUNDS FOR HEALTH AND HUMAN SERVICES', '3639', 'Class Status', NULL, 'WB WEB', 'Priscilla Barnes', 38, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Develop skills to acquire and manage external funds for health and human services research and development in academic, public-, not-for-profit, and private-sector agencies, including establishing a research or development career trajectory; identifying sources of funds in areas of interest; preparing a proposal and budget for funding; and managing funded projects.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 662', 'ACQUIRING & MANAGING EXTERNAL FUNDS FOR HEALTH AND HUMAN SERVICES', '34902', 'Closed', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'HD TBA', 'Priscilla Barnes', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Develop skills to acquire and manage external funds for health and human services research and development in academic, public-, not-for-profit, and private-sector agencies, including establishing a research or development career trajectory; identifying sources of funds in areas of interest; preparing a proposal and budget for funding; and managing funded projects.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 710', 'PEDAGOGY IN HEALTH BEHAVIOR', '8340', 'Class Status', 'Tu Tuesday 11:30 AM–2:00 PM', 'LH 328', 'Catherine Sherwood-Laughlin', 13, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Provides doctoral students with knowledge required to think critically about teaching practice and enhance pedagogical skills. Rooted in the scholarship of teaching and learning, will help students prepare for teaching, feel more comfortable in the classroom and utilize pedagogical best practices in a supportive environment.', ARRAY[]::TEXT[], NULL),
    ('SPH-H 791', 'READINGS IN HEALTH BEHAVIOR', '6216', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Readings', '1–10', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
